import React, { useState, useEffect, useRef } from 'react';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Settings2, 
  History, 
  Download, 
  Copy, 
  ChevronRight, 
  ChevronDown, 
  RefreshCw, 
  Trash2, 
  Layers,
  Eraser,
  Maximize2,
  Check,
  AlertCircle,
  Clock,
  Menu,
  X,
  Plus,
  Zap,
  Star
} from 'lucide-react';
import { 
  GeneratedImage, 
  GenerationSettings, 
  AspectRatio, 
  Resolution, 
  GenerationMode,
  PromptHistoryItem,
  FeaturedPrompt
} from './types';
import { 
  STYLE_PRESETS, 
  MOODS, 
  LIGHTING, 
  COLOR_TONES, 
  ASPECT_RATIOS, 
  RESOLUTIONS,
  FEATURED_PROMPTS
} from './constants';
import { generateImage, enhancePrompt, translatePrompt } from './geminiService';

const App: React.FC = () => {
  // --- UI State ---
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isAdvancedMode, setAdvancedMode] = useState(false);
  const [activeTab, setActiveTab] = useState<'generate' | 'gallery'>('generate');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // --- Generation State ---
  const [prompt, setPrompt] = useState('');
  const [mode, setMode] = useState<GenerationMode>('text-to-image');
  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: '1:1',
    resolution: '1K',
    style: 'none',
    mood: 'Default',
    lighting: 'Default',
    colorTone: 'Default',
    negativePrompt: '',
    seed: null,
    numImages: 1,
    useProModel: false,
  });

  // --- Image Handling ---
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [maskImage, setMaskImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentResult, setCurrentResult] = useState<string[]>([]);
  const [history, setHistory] = useState<PromptHistoryItem[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load History from Local Storage
  useEffect(() => {
    const savedGallery = localStorage.getItem('dreamgen_gallery');
    if (savedGallery) setGeneratedImages(JSON.parse(savedGallery));

    const savedHistory = localStorage.getItem('dreamgen_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const saveToGallery = (urls: string[], currentPrompt: string) => {
    const newItems: GeneratedImage[] = urls.map(url => ({
      id: Math.random().toString(36).substr(2, 9),
      url,
      prompt: currentPrompt,
      timestamp: Date.now(),
      settings: { ...settings },
      originalImage: uploadedImage || undefined
    }));
    const updatedGallery = [...newItems, ...generatedImages].slice(0, 50);
    setGeneratedImages(updatedGallery);
    localStorage.setItem('dreamgen_gallery', JSON.stringify(updatedGallery));

    const newHistoryItem = { prompt: currentPrompt, timestamp: Date.now() };
    const updatedHistory = [newHistoryItem, ...history.filter(h => h.prompt !== currentPrompt)].slice(0, 10);
    setHistory(updatedHistory);
    localStorage.setItem('dreamgen_history', JSON.stringify(updatedHistory));
  };

  const applyTemplate = (template: FeaturedPrompt) => {
    setPrompt(template.prompt);
    setSettings({
      ...settings,
      aspectRatio: template.aspectRatio,
      style: template.style
    });
    setActiveTab('generate');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleEnhancePrompt = async () => {
    if (!prompt.trim()) return;
    setIsLoading(true);
    const enhanced = await enhancePrompt(prompt);
    setPrompt(enhanced);
    setIsLoading(false);
  };

  const handleGenerate = async () => {
    if (!prompt.trim() && !uploadedImage) {
      setError("Please enter a prompt or upload an image.");
      return;
    }

    if (settings.useProModel && typeof window !== 'undefined' && (window as any).aistudio) {
       const hasKey = await (window as any).aistudio.hasSelectedApiKey();
       if (!hasKey) {
          await (window as any).aistudio.openSelectKey();
       }
    }

    setIsLoading(true);
    setError(null);
    setCurrentResult([]);

    try {
      const translated = await translatePrompt(prompt);
      const results = await generateImage(translated, settings, mode, uploadedImage || undefined, maskImage || undefined);
      setCurrentResult(results);
      saveToGallery(results, prompt);
    } catch (err: any) {
      setError(err.message || "Generation failed. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (readerEvent) => {
        setUploadedImage(readerEvent.target?.result as string);
        setMode('image-to-image');
      };
      reader.readAsDataURL(file);
    }
  };

  const downloadImage = (url: string, format: string = 'png') => {
    const link = document.createElement('a');
    link.href = url;
    link.download = `dreamgen-${Date.now()}.${format}`;
    link.click();
  };

  const copyToClipboard = async (url: string) => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      await navigator.clipboard.write([
        new ClipboardItem({ [blob.type]: blob })
      ]);
      alert("Image copied to clipboard!");
    } catch (err) {
      alert("Failed to copy image.");
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-950 text-slate-200">
      {/* Mobile Header */}
      <div className="lg:hidden fixed top-0 left-0 right-0 h-16 glass-panel z-50 flex items-center justify-between px-4">
        <div className="flex items-center gap-2">
          <Sparkles className="text-blue-500 w-6 h-6" />
          <span className="font-bold text-xl tracking-tight">DreamGen AI</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Sidebar Controls */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-80 glass-panel border-r border-slate-800 transition-transform duration-300 lg:relative lg:translate-x-0
        ${isMobileMenuOpen ? 'translate-x-0 pt-20' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="h-full flex flex-col p-6 space-y-8 overflow-y-auto">
          <div className="hidden lg:flex items-center gap-2 mb-4">
            <Sparkles className="text-blue-500 w-8 h-8" />
            <span className="font-bold text-2xl tracking-tight">DreamGen AI</span>
          </div>

          {/* Style Presets */}
          <section>
            <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Layers className="w-4 h-4" /> Style Presets
            </h3>
            <div className="grid grid-cols-2 gap-3">
              {STYLE_PRESETS.map((style) => (
                <button
                  key={style.id}
                  onClick={() => setSettings({ ...settings, style: style.id })}
                  className={`
                    group relative aspect-square rounded-xl overflow-hidden border-2 transition-all duration-200
                    ${settings.style === style.id ? 'border-blue-500 ring-2 ring-blue-500/20' : 'border-slate-800 hover:border-slate-700'}
                  `}
                >
                  <img src={style.previewUrl} alt={style.name} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent flex items-end p-2">
                    <span className="text-[10px] font-medium truncate w-full">{style.name}</span>
                  </div>
                  {settings.style === style.id && (
                    <div className="absolute top-1 right-1 bg-blue-500 rounded-full p-0.5">
                      <Check className="w-3 h-3 text-white" />
                    </div>
                  )}
                </button>
              ))}
            </div>
          </section>

          {/* Aspect Ratio */}
          <section>
            <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4">Aspect Ratio</h3>
            <div className="grid grid-cols-4 gap-2">
              {ASPECT_RATIOS.map((ratio) => (
                <button
                  key={ratio.value}
                  onClick={() => setSettings({ ...settings, aspectRatio: ratio.value })}
                  className={`
                    py-2 px-1 rounded-lg text-xs font-medium border transition-colors
                    ${settings.aspectRatio === ratio.value ? 'bg-blue-500/10 border-blue-500 text-blue-400' : 'bg-slate-900 border-slate-800 hover:border-slate-700'}
                  `}
                >
                  {ratio.label}
                </button>
              ))}
            </div>
          </section>

          {/* Model Selection */}
          <section>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Model Quality</h3>
              <div 
                className={`w-10 h-5 rounded-full p-1 cursor-pointer transition-colors ${settings.useProModel ? 'bg-purple-600' : 'bg-slate-700'}`}
                onClick={() => setSettings({ ...settings, useProModel: !settings.useProModel })}
              >
                <div className={`w-3 h-3 bg-white rounded-full transition-transform ${settings.useProModel ? 'translate-x-5' : 'translate-x-0'}`} />
              </div>
            </div>
            <div className="text-[10px] text-slate-500 mb-2 italic">
              {settings.useProModel ? 'Gemini 3 Pro: 4K, high fidelity' : 'Gemini 2.5 Flash: Fast, efficient'}
            </div>
            {settings.useProModel && (
              <div className="grid grid-cols-3 gap-2 mt-2">
                {RESOLUTIONS.map((res) => (
                  <button
                    key={res}
                    onClick={() => setSettings({ ...settings, resolution: res })}
                    className={`
                      py-1 rounded-lg text-[10px] border transition-colors
                      ${settings.resolution === res ? 'bg-purple-500/10 border-purple-500 text-purple-400' : 'bg-slate-900 border-slate-800'}
                    `}
                  >
                    {res}
                  </button>
                ))}
              </div>
            )}
          </section>

          {/* Creative Tweaks */}
          <section className="space-y-4">
             <div className="flex flex-col gap-2">
                <label className="text-xs font-semibold text-slate-500">Mood</label>
                <select 
                  value={settings.mood}
                  onChange={(e) => setSettings({...settings, mood: e.target.value})}
                  className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                >
                  {MOODS.map(m => <option key={m} value={m}>{m}</option>)}
                </select>
             </div>
             <div className="flex flex-col gap-2">
                <label className="text-xs font-semibold text-slate-500">Lighting</label>
                <select 
                  value={settings.lighting}
                  onChange={(e) => setSettings({...settings, lighting: e.target.value})}
                  className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                >
                  {LIGHTING.map(l => <option key={l} value={l}>{l}</option>)}
                </select>
             </div>
          </section>

          <button 
            onClick={() => setAdvancedMode(!isAdvancedMode)}
            className="flex items-center justify-between text-xs font-semibold text-slate-500 hover:text-slate-300 py-2 border-t border-slate-800"
          >
            <span>Advanced Controls</span>
            {isAdvancedMode ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
          </button>

          {isAdvancedMode && (
            <div className="space-y-4 pt-2 animate-in slide-in-from-top-2 duration-300">
               <div className="flex flex-col gap-2">
                  <label className="text-xs font-semibold text-slate-500">Negative Prompt</label>
                  <textarea 
                    value={settings.negativePrompt}
                    onChange={(e) => setSettings({...settings, negativePrompt: e.target.value})}
                    placeholder="Avoid these elements..."
                    className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-xs h-20 resize-none focus:ring-1 focus:ring-red-500 outline-none"
                  />
               </div>
               <div className="flex items-center justify-between">
                  <label className="text-xs font-semibold text-slate-500">Batch Count</label>
                  <input 
                    type="number" min="1" max="4"
                    value={settings.numImages}
                    onChange={(e) => setSettings({...settings, numImages: parseInt(e.target.value)})}
                    className="w-16 bg-slate-900 border border-slate-800 rounded-lg p-1 text-xs text-center"
                  />
               </div>
            </div>
          )}
        </div>
      </aside>

      {/* Main Workspace */}
      <main className="flex-1 flex flex-col min-w-0 overflow-y-auto">
        <header className="p-4 lg:p-8 flex items-center justify-between border-b border-slate-900/50 sticky top-0 bg-slate-950/80 backdrop-blur-md z-30">
          <nav className="flex gap-8">
            <button 
              onClick={() => setActiveTab('generate')}
              className={`pb-2 text-sm font-semibold transition-colors border-b-2 ${activeTab === 'generate' ? 'text-blue-500 border-blue-500' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
            >
              Studio
            </button>
            <button 
              onClick={() => setActiveTab('gallery')}
              className={`pb-2 text-sm font-semibold transition-colors border-b-2 ${activeTab === 'gallery' ? 'text-blue-500 border-blue-500' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
            >
              Vault
            </button>
          </nav>

          <div className="hidden sm:flex items-center gap-4 text-xs font-medium">
             <div className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-500/10 text-blue-400 rounded-full">
                <Zap className="w-3 h-3" />
                <span>Credits: Unlimited</span>
             </div>
          </div>
        </header>

        <div className="flex-1 p-4 lg:p-8 max-w-6xl mx-auto w-full space-y-12">
          {activeTab === 'generate' ? (
            <>
              {/* Prompt Input Area */}
              <div className="space-y-6">
                <div className="relative group">
                  <div className="absolute -inset-1 bg-gradient-to-r from-blue-500 to-purple-600 rounded-2xl blur opacity-10 group-focus-within:opacity-25 transition duration-500"></div>
                  <textarea
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="Visualize your imagination..."
                    className="relative w-full h-40 bg-slate-900/80 border-2 border-slate-800 rounded-2xl p-6 text-xl focus:border-blue-500 outline-none resize-none transition-all pr-40 placeholder:text-slate-700"
                  />
                  <div className="absolute bottom-4 right-4 flex gap-2">
                    <button 
                      onClick={handleEnhancePrompt}
                      disabled={isLoading}
                      className="flex items-center gap-1.5 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-xl text-xs font-semibold transition-all disabled:opacity-50 border border-slate-700"
                    >
                      <Sparkles className="w-3.5 h-3.5 text-blue-400" />
                      {isLoading ? 'Enhancing...' : 'Enhance'}
                    </button>
                  </div>
                </div>

                <div className="flex flex-wrap items-center justify-between gap-4">
                   <div className="flex items-center gap-3">
                      <input 
                        type="file" 
                        onChange={handleFileUpload} 
                        className="hidden" 
                        id="img-upload"
                        accept="image/*"
                      />
                      <label 
                        htmlFor="img-upload"
                        className={`cursor-pointer flex items-center gap-2 px-5 py-3 rounded-2xl border-2 transition-all ${uploadedImage ? 'bg-green-500/10 border-green-500 text-green-400' : 'bg-slate-900 border-slate-800 hover:border-slate-700'}`}
                      >
                        <ImageIcon className="w-5 h-5" />
                        <span className="text-sm font-bold">{uploadedImage ? 'Image Loaded' : 'Reference Image'}</span>
                      </label>

                      {uploadedImage && (
                        <div className="flex gap-2">
                          <button 
                            onClick={() => { setUploadedImage(null); setMode('text-to-image'); }}
                            className="p-3 rounded-2xl bg-red-500/10 border-2 border-red-500/30 text-red-400 hover:bg-red-500/20 transition-all"
                          >
                            <Trash2 className="w-5 h-5" />
                          </button>
                          <div className="flex items-center gap-3 bg-slate-900 border border-slate-800 px-4 py-2 rounded-2xl">
                            <span className="text-xs font-bold text-slate-500 uppercase tracking-tighter">Mode</span>
                            <select 
                              value={mode} 
                              onChange={(e) => setMode(e.target.value as GenerationMode)}
                              className="bg-transparent text-sm font-bold outline-none"
                            >
                              <option value="image-to-image">Img2Img</option>
                              <option value="inpainting">Inpaint</option>
                              <option value="outpainting">Outpaint</option>
                            </select>
                          </div>
                        </div>
                      )}
                   </div>

                   <button 
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className="gradient-border group min-w-[200px]"
                   >
                    <div className="flex items-center justify-center gap-3 px-10 py-4 group-hover:bg-transparent transition-colors">
                      {isLoading ? (
                        <RefreshCw className="w-6 h-6 animate-spin text-white" />
                      ) : (
                        <Sparkles className="w-6 h-6 text-white" />
                      )}
                      <span className="font-extrabold text-lg text-white">{isLoading ? 'Creating...' : 'Generate'}</span>
                    </div>
                   </button>
                </div>
              </div>

              {/* Status / Results */}
              <div className="min-h-[500px] flex flex-col items-center justify-center border-2 border-slate-900 rounded-[2.5rem] p-4 lg:p-12 bg-slate-900/10 relative overflow-hidden">
                {error && (
                  <div className="mb-6 p-4 bg-red-500/10 border border-red-500/30 rounded-2xl flex items-center gap-3 text-red-400 max-w-md w-full animate-in fade-in zoom-in duration-300">
                    <AlertCircle className="w-6 h-6 flex-shrink-0" />
                    <p className="text-sm font-medium">{error}</p>
                  </div>
                )}

                {!isLoading && currentResult.length === 0 && !error && (
                  <div className="text-center space-y-6 max-w-sm">
                    <div className="w-24 h-24 bg-slate-900 rounded-3xl flex items-center justify-center mx-auto mb-8 shadow-inner border border-slate-800">
                      <ImageIcon className="w-10 h-10 text-slate-700" />
                    </div>
                    <h3 className="text-2xl font-black text-slate-200 uppercase tracking-tight">Your Canvas Awaits</h3>
                    <p className="text-slate-500 text-sm font-medium leading-relaxed">Turn your words into high-resolution visuals using next-generation Gemini AI.</p>
                  </div>
                )}

                {isLoading && (
                  <div className="text-center space-y-8">
                    <div className="relative w-40 h-40 mx-auto">
                      <div className="absolute inset-0 border-[6px] border-blue-500/10 rounded-full"></div>
                      <div className="absolute inset-0 border-[6px] border-blue-500 border-t-transparent border-r-transparent rounded-full animate-spin"></div>
                      <div className="absolute inset-4 border-[6px] border-purple-500/10 rounded-full"></div>
                      <div className="absolute inset-4 border-[6px] border-purple-500 border-b-transparent border-l-transparent animate-[spin_1.5s_linear_infinite_reverse] rounded-full"></div>
                      <div className="absolute inset-0 flex items-center justify-center">
                        <Sparkles className="w-8 h-8 text-blue-400 animate-pulse" />
                      </div>
                    </div>
                    <div>
                      <h3 className="text-xl font-black text-white uppercase tracking-wider">Dreaming in Silicon...</h3>
                      <div className="flex justify-center gap-1 mt-3">
                         {[0, 1, 2].map(i => (
                           <div key={i} className={`w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce`} style={{animationDelay: `${i * 0.2}s`}} />
                         ))}
                      </div>
                    </div>
                  </div>
                )}

                {!isLoading && currentResult.length > 0 && (
                  <div className={`grid gap-8 w-full ${currentResult.length > 1 ? 'grid-cols-2' : 'grid-cols-1'}`}>
                    {currentResult.map((url, idx) => (
                      <div key={idx} className="group relative rounded-3xl overflow-hidden bg-slate-900 shadow-[0_0_50px_-12px_rgba(0,0,0,0.5)] border border-slate-800 animate-in fade-in slide-in-from-bottom-4 duration-700">
                        <img src={url} alt={`Result ${idx}`} className="w-full h-auto object-contain select-none" />
                        <div className="absolute inset-x-0 bottom-0 p-6 bg-gradient-to-t from-black/95 via-black/40 to-transparent translate-y-full group-hover:translate-y-0 transition-all duration-500 flex items-center justify-between backdrop-blur-[2px]">
                           <div className="flex flex-col">
                              <span className="text-xs font-black text-blue-400 uppercase tracking-widest">Masterpiece</span>
                              <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Generated in 1K Resolution</span>
                           </div>
                           <div className="flex gap-3">
                              <button 
                                onClick={() => downloadImage(url)}
                                className="p-3 bg-white/10 hover:bg-blue-500 hover:text-white rounded-2xl backdrop-blur-md transition-all border border-white/5"
                                title="Download"
                              >
                                <Download className="w-5 h-5" />
                              </button>
                              <button 
                                onClick={() => copyToClipboard(url)}
                                className="p-3 bg-white/10 hover:bg-blue-500 hover:text-white rounded-2xl backdrop-blur-md transition-all border border-white/5"
                                title="Copy"
                              >
                                <Copy className="w-5 h-5" />
                              </button>
                           </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Inspiration Section */}
              <section className="space-y-6">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <Star className="w-6 h-6 text-yellow-500 fill-yellow-500" />
                    <h4 className="text-xl font-black uppercase tracking-tight">Studio Inspiration</h4>
                  </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                   {FEATURED_PROMPTS.map((item) => (
                     <div 
                      key={item.id} 
                      className="group relative rounded-3xl overflow-hidden bg-slate-900 border border-slate-800 hover:border-blue-500/50 transition-all cursor-pointer h-64"
                      onClick={() => applyTemplate(item)}
                     >
                       <img src={item.previewUrl} alt={item.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 opacity-60 group-hover:opacity-80" />
                       <div className="absolute inset-0 p-6 flex flex-col justify-end bg-gradient-to-t from-black/90 via-black/20 to-transparent">
                          <h5 className="text-lg font-black text-white leading-none mb-2">{item.title}</h5>
                          <p className="text-xs text-slate-400 line-clamp-2 font-medium mb-4">{item.prompt}</p>
                          <div className="flex items-center gap-2">
                             <span className="px-2 py-1 bg-blue-500/20 text-blue-400 text-[10px] font-black uppercase rounded-md border border-blue-500/30">Try Prompt</span>
                             <span className="px-2 py-1 bg-white/10 text-white text-[10px] font-black uppercase rounded-md border border-white/5">{item.aspectRatio}</span>
                          </div>
                       </div>
                     </div>
                   ))}
                </div>
              </section>

              {/* Recent Activity */}
              {history.length > 0 && (
                <section className="space-y-4">
                  <div className="flex items-center gap-2 text-slate-500">
                    <Clock className="w-4 h-4" />
                    <h4 className="text-xs font-black uppercase tracking-widest">Recent Session History</h4>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {history.map((item, i) => (
                      <button 
                        key={i} 
                        onClick={() => setPrompt(item.prompt)}
                        className="px-5 py-2.5 bg-slate-900 border border-slate-800 rounded-2xl text-xs font-bold text-slate-400 hover:text-white hover:border-slate-600 transition-all max-w-xs truncate"
                      >
                        {item.prompt}
                      </button>
                    ))}
                  </div>
                </section>
              )}
            </>
          ) : (
            /* Gallery Tab */
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-8">
              {generatedImages.length === 0 ? (
                <div className="col-span-full py-32 text-center text-slate-500 space-y-6">
                   <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mx-auto shadow-inner">
                      <Trash2 className="w-10 h-10 text-slate-800" />
                   </div>
                   <div className="space-y-1">
                      <p className="text-lg font-black text-slate-400 uppercase tracking-tight">Your vault is empty</p>
                      <p className="text-sm font-medium">Generated images will appear here for you to download later.</p>
                   </div>
                   <button onClick={() => setActiveTab('generate')} className="px-8 py-3 bg-blue-500 text-white rounded-2xl font-black uppercase tracking-tighter hover:bg-blue-600 transition-all">Start Creating</button>
                </div>
              ) : (
                generatedImages.map((img) => (
                  <div key={img.id} className="group relative aspect-square rounded-[2rem] overflow-hidden bg-slate-900 border border-slate-800 hover:border-blue-500 transition-all animate-in zoom-in duration-500 shadow-xl">
                    <img src={img.url} alt={img.prompt} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/80 opacity-0 group-hover:opacity-100 transition-all p-6 flex flex-col justify-between backdrop-blur-[4px]">
                       <p className="text-xs line-clamp-4 font-bold text-slate-200 leading-relaxed italic">"{img.prompt}"</p>
                       <div className="flex gap-3">
                          <button onClick={() => downloadImage(img.url)} className="p-3 bg-white/10 rounded-2xl hover:bg-blue-500 text-white transition-all border border-white/5"><Download className="w-4 h-4" /></button>
                          <button onClick={() => { setPrompt(img.prompt); setActiveTab('generate'); }} className="p-3 bg-white/10 rounded-2xl hover:bg-blue-500 text-white transition-all border border-white/5"><RefreshCw className="w-4 h-4" /></button>
                       </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

export type AspectRatio = '1:1' | '4:3' | '3:4' | '16:9' | '9:16';
export type Resolution = '1K' | '2K' | '4K';
export type GenerationMode = 'text-to-image' | 'image-to-image' | 'inpainting' | 'outpainting';

export interface StylePreset {
  id: string;
  name: string;
  promptSuffix: string;
  previewUrl: string;
}

export interface GenerationSettings {
  aspectRatio: AspectRatio;
  resolution: Resolution;
  style: string;
  mood: string;
  lighting: string;
  colorTone: string;
  negativePrompt: string;
  seed: number | null;
  numImages: number;
  useProModel: boolean;
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  timestamp: number;
  settings: GenerationSettings;
  originalImage?: string; // For img2img/inpainting variations
}

export interface PromptHistoryItem {
  prompt: string;
  timestamp: number;
}

import { StylePreset } from './types';

export const STYLE_PRESETS: StylePreset[] = [
  { id: 'none', name: 'None', promptSuffix: '', previewUrl: 'https://picsum.photos/seed/style1/200' },
  { id: 'photo', name: 'Realistic Photo', promptSuffix: 'high resolution, photorealistic, 8k, detailed skin textures, cinematic lighting', previewUrl: 'https://picsum.photos/seed/photo/200' },
  { id: 'anime', name: 'Anime', promptSuffix: 'studio ghibli style, vibrant colors, detailed lineart, expressive characters', previewUrl: 'https://picsum.photos/seed/anime/200' },
  { id: 'cinematic', name: 'Cinematic', promptSuffix: 'hollywood movie still, dramatic lighting, anamorphic lens flares, high contrast', previewUrl: 'https://picsum.photos/seed/cinema/200' },
  { id: 'dslr', name: 'DSLR Portrait', promptSuffix: 'shallow depth of field, bokeh background, sharp focus, professional photography', previewUrl: 'https://picsum.photos/seed/dslr/200' },
  { id: 'oil', name: 'Oil Painting', promptSuffix: 'textured brushstrokes, thick paint, classic oil painting masterpiece, rich colors', previewUrl: 'https://picsum.photos/seed/oil/200' },
  { id: 'watercolor', name: 'Watercolor', promptSuffix: 'soft edges, bleeding colors, artistic paper texture, delicate washes', previewUrl: 'https://picsum.photos/seed/water/200' },
  { id: '3d', name: '3D Render', promptSuffix: 'octane render, unreal engine 5, raytracing, highly detailed, stylized 3D', previewUrl: 'https://picsum.photos/seed/3d/200' },
];

export const MOODS = ['Default', 'Vibrant', 'Dark', 'Soft', 'Dramatic', 'Ethereal', 'Gritty'];
export const LIGHTING = ['Default', 'Studio', 'Natural', 'Sunset', 'Neon', 'God Rays', 'Muted'];
export const COLOR_TONES = ['Default', 'Warm', 'Cool', 'Pastel', 'Monochrome', 'Vintage', 'High Saturation'];

export const ASPECT_RATIOS = [
  { label: '1:1 (4:4)', value: '1:1' as const, icon: 'Square' },
  { label: '4:3', value: '4:3' as const, icon: 'Monitor' },
  { label: '3:4', value: '3:4' as const, icon: 'Smartphone' },
  { label: '16:9', value: '16:9' as const, icon: 'Monitor' },
  { label: '9:16', value: '9:16' as const, icon: 'Smartphone' },
];

export const RESOLUTIONS = ['1K', '2K', '4K'] as const;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Settings2, 
  History, 
  Download, 
  Copy, 
  ChevronRight, 
  ChevronDown, 
  RefreshCw, 
  Trash2, 
  Layers,
  Eraser,
  Maximize2,
  Check,
  AlertCircle,
  Clock,
  Menu,
  X,
  Plus
} from 'lucide-react';
import { 
  GeneratedImage, 
  GenerationSettings, 
  AspectRatio, 
  Resolution, 
  GenerationMode,
  PromptHistoryItem
} from './types';
import { 
  STYLE_PRESETS, 
  MOODS, 
  LIGHTING, 
  COLOR_TONES, 
  ASPECT_RATIOS, 
  RESOLUTIONS 
} from './constants';
import { generateImage, enhancePrompt, translatePrompt } from './geminiService';

const App: React.FC = () => {
  // --- UI State ---
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isAdvancedMode, setAdvancedMode] = useState(false);
  const [activeTab, setActiveTab] = useState<'generate' | 'gallery'>('generate');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // --- Generation State ---
  const [prompt, setPrompt] = useState('');
  const [mode, setMode] = useState<GenerationMode>('text-to-image');
  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: '1:1',
    resolution: '1K',
    style: 'none',
    mood: 'Default',
    lighting: 'Default',
    colorTone: 'Default',
    negativePrompt: '',
    seed: null,
    numImages: 1,
    useProModel: false,
  });

  // --- Image Handling ---
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [maskImage, setMaskImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentResult, setCurrentResult] = useState<string[]>([]);
  const [history, setHistory] = useState<PromptHistoryItem[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Load History from Local Storage
  useEffect(() => {
    const savedGallery = localStorage.getItem('dreamgen_gallery');
    if (savedGallery) setGeneratedImages(JSON.parse(savedGallery));

    const savedHistory = localStorage.getItem('dreamgen_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const saveToGallery = (urls: string[], currentPrompt: string) => {
    const newItems: GeneratedImage[] = urls.map(url => ({
      id: Math.random().toString(36).substr(2, 9),
      url,
      prompt: currentPrompt,
      timestamp: Date.now(),
      settings: { ...settings },
      originalImage: uploadedImage || undefined
    }));
    const updatedGallery = [...newItems, ...generatedImages].slice(0, 50);
    setGeneratedImages(updatedGallery);
    localStorage.setItem('dreamgen_gallery', JSON.stringify(updatedGallery));

    const newHistoryItem = { prompt: currentPrompt, timestamp: Date.now() };
    const updatedHistory = [newHistoryItem, ...history.filter(h => h.prompt !== currentPrompt)].slice(0, 10);
    setHistory(updatedHistory);
    localStorage.setItem('dreamgen_history', JSON.stringify(updatedHistory));
  };

  const handleEnhancePrompt = async () => {
    if (!prompt.trim()) return;
    setIsLoading(true);
    const enhanced = await enhancePrompt(prompt);
    setPrompt(enhanced);
    setIsLoading(false);
  };

  const handleGenerate = async () => {
    if (!prompt.trim() && !uploadedImage) {
      setError("Please enter a prompt or upload an image.");
      return;
    }

    // Pro model requires explicit API key check conceptually in some environments,
    // but here we follow standard process.env.API_KEY logic.
    if (settings.useProModel && typeof window !== 'undefined' && (window as any).aistudio) {
       const hasKey = await (window as any).aistudio.hasSelectedApiKey();
       if (!hasKey) {
          await (window as any).aistudio.openSelectKey();
          // We proceed assuming user might have picked one or it's handled by env
       }
    }

    setIsLoading(true);
    setError(null);
    setCurrentResult([]);

    try {
      const translated = await translatePrompt(prompt);
      const results = await generateImage(translated, settings, mode, uploadedImage || undefined, maskImage || undefined);
      setCurrentResult(results);
      saveToGallery(results, prompt);
    } catch (err: any) {
      setError(err.message || "Generation failed. Please try again.");
      if (err.message?.includes("Requested entity was not found") && settings.useProModel) {
          setError("API Key configuration required for Pro model.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (readerEvent) => {
        setUploadedImage(readerEvent.target?.result as string);
        setMode('image-to-image');
      };
      reader.readAsDataURL(file);
    }
  };

  const downloadImage = (url: string, format: string = 'png') => {
    const link = document.createElement('a');
    link.href = url;
    link.download = `dreamgen-${Date.now()}.${format}`;
    link.click();
  };

  const copyToClipboard = async (url: string) => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      await navigator.clipboard.write([
        new ClipboardItem({ [blob.type]: blob })
      ]);
      alert("Image copied to clipboard!");
    } catch (err) {
      alert("Failed to copy image.");
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-950 text-slate-200">
      {/* Mobile Header */}
      <div className="lg:hidden fixed top-0 left-0 right-0 h-16 glass-panel z-50 flex items-center justify-between px-4">
        <div className="flex items-center gap-2">
          <Sparkles className="text-blue-500 w-6 h-6" />
          <span className="font-bold text-xl tracking-tight">DreamGen AI</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Sidebar Controls */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-80 glass-panel border-r border-slate-800 transition-transform duration-300 lg:relative lg:translate-x-0
        ${isMobileMenuOpen ? 'translate-x-0 pt-20' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="h-full flex flex-col p-6 space-y-8 overflow-y-auto">
          <div className="hidden lg:flex items-center gap-2 mb-4">
            <Sparkles className="text-blue-500 w-8 h-8" />
            <span className="font-bold text-2xl tracking-tight">DreamGen AI</span>
          </div>

          {/* Style Presets */}
          <section>
            <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Layers className="w-4 h-4" /> Style Presets
            </h3>
            <div className="grid grid-cols-2 gap-3">
              {STYLE_PRESETS.map((style) => (
                <button
                  key={style.id}
                  onClick={() => setSettings({ ...settings, style: style.id })}
                  className={`
                    group relative aspect-square rounded-xl overflow-hidden border-2 transition-all duration-200
                    ${settings.style === style.id ? 'border-blue-500 ring-2 ring-blue-500/20' : 'border-slate-800 hover:border-slate-700'}
                  `}
                >
                  <img src={style.previewUrl} alt={style.name} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent flex items-end p-2">
                    <span className="text-[10px] font-medium truncate w-full">{style.name}</span>
                  </div>
                  {settings.style === style.id && (
                    <div className="absolute top-1 right-1 bg-blue-500 rounded-full p-0.5">
                      <Check className="w-3 h-3 text-white" />
                    </div>
                  )}
                </button>
              ))}
            </div>
          </section>

          {/* Aspect Ratio */}
          <section>
            <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4">Aspect Ratio</h3>
            <div className="grid grid-cols-3 gap-2">
              {ASPECT_RATIOS.map((ratio) => (
                <button
                  key={ratio.value}
                  onClick={() => setSettings({ ...settings, aspectRatio: ratio.value })}
                  className={`
                    py-2 px-1 rounded-lg text-[10px] font-medium border transition-colors
                    ${settings.aspectRatio === ratio.value ? 'bg-blue-500/10 border-blue-500 text-blue-400' : 'bg-slate-900 border-slate-800 hover:border-slate-700'}
                  `}
                >
                  {ratio.label}
                </button>
              ))}
            </div>
          </section>

          {/* Model Selection */}
          <section>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Model Quality</h3>
              <div 
                className={`w-10 h-5 rounded-full p-1 cursor-pointer transition-colors ${settings.useProModel ? 'bg-purple-600' : 'bg-slate-700'}`}
                onClick={() => setSettings({ ...settings, useProModel: !settings.useProModel })}
              >
                <div className={`w-3 h-3 bg-white rounded-full transition-transform ${settings.useProModel ? 'translate-x-5' : 'translate-x-0'}`} />
              </div>
            </div>
            <div className="text-[10px] text-slate-500 mb-2 italic">
              {settings.useProModel ? 'Gemini 3 Pro: High quality, 4K support, requires billing' : 'Gemini 2.5 Flash: Fast, efficient, daily limits'}
            </div>
            {settings.useProModel && (
              <div className="grid grid-cols-3 gap-2 mt-2">
                {RESOLUTIONS.map((res) => (
                  <button
                    key={res}
                    onClick={() => setSettings({ ...settings, resolution: res })}
                    className={`
                      py-1 rounded-lg text-[10px] border transition-colors
                      ${settings.resolution === res ? 'bg-purple-500/10 border-purple-500 text-purple-400' : 'bg-slate-900 border-slate-800'}
                    `}
                  >
                    {res}
                  </button>
                ))}
              </div>
            )}
          </section>

          {/* Creative Tweaks */}
          <section className="space-y-4">
             <div className="flex flex-col gap-2">
                <label className="text-xs font-semibold text-slate-500">Mood</label>
                <select 
                  value={settings.mood}
                  onChange={(e) => setSettings({...settings, mood: e.target.value})}
                  className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                >
                  {MOODS.map(m => <option key={m} value={m}>{m}</option>)}
                </select>
             </div>
             <div className="flex flex-col gap-2">
                <label className="text-xs font-semibold text-slate-500">Lighting</label>
                <select 
                  value={settings.lighting}
                  onChange={(e) => setSettings({...settings, lighting: e.target.value})}
                  className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                >
                  {LIGHTING.map(l => <option key={l} value={l}>{l}</option>)}
                </select>
             </div>
          </section>

          {/* Advanced Mode Toggle */}
          <button 
            onClick={() => setAdvancedMode(!isAdvancedMode)}
            className="flex items-center justify-between text-xs font-semibold text-slate-500 hover:text-slate-300 py-2 border-t border-slate-800"
          >
            <span>Advanced Controls</span>
            {isAdvancedMode ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
          </button>

          {isAdvancedMode && (
            <div className="space-y-4 pt-2 animate-in slide-in-from-top-2 duration-300">
               <div className="flex flex-col gap-2">
                  <label className="text-xs font-semibold text-slate-500">Negative Prompt</label>
                  <textarea 
                    value={settings.negativePrompt}
                    onChange={(e) => setSettings({...settings, negativePrompt: e.target.value})}
                    placeholder="Avoid these elements..."
                    className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-xs h-20 resize-none focus:ring-1 focus:ring-red-500 outline-none"
                  />
               </div>
               <div className="flex items-center justify-between">
                  <label className="text-xs font-semibold text-slate-500">Batch Count</label>
                  <input 
                    type="number" min="1" max="4"
                    value={settings.numImages}
                    onChange={(e) => setSettings({...settings, numImages: parseInt(e.target.value)})}
                    className="w-16 bg-slate-900 border border-slate-800 rounded-lg p-1 text-xs text-center"
                  />
               </div>
            </div>
          )}
        </div>
      </aside>

      {/* Main Workspace */}
      <main className="flex-1 flex flex-col min-w-0 overflow-y-auto">
        <header className="p-4 lg:p-8 flex items-center justify-between border-b border-slate-900/50">
          <nav className="flex gap-8">
            <button 
              onClick={() => setActiveTab('generate')}
              className={`pb-2 text-sm font-semibold transition-colors border-b-2 ${activeTab === 'generate' ? 'text-blue-500 border-blue-500' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
            >
              Generate
            </button>
            <button 
              onClick={() => setActiveTab('gallery')}
              className={`pb-2 text-sm font-semibold transition-colors border-b-2 ${activeTab === 'gallery' ? 'text-blue-500 border-blue-500' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
            >
              Gallery
            </button>
          </nav>
        </header>

        <div className="flex-1 p-4 lg:p-8 max-w-6xl mx-auto w-full space-y-8">
          {activeTab === 'generate' ? (
            <>
              {/* Prompt Input Area */}
              <div className="space-y-4">
                <div className="relative group">
                  <textarea
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="Describe what you want to see..."
                    className="w-full h-32 bg-slate-900/50 border-2 border-slate-800 rounded-2xl p-6 text-lg focus:border-blue-500 outline-none resize-none transition-all pr-32"
                  />
                  <div className="absolute bottom-4 right-4 flex gap-2">
                    <button 
                      onClick={handleEnhancePrompt}
                      disabled={isLoading}
                      className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-500/10 hover:bg-blue-500/20 text-blue-400 rounded-full text-xs font-medium transition-colors disabled:opacity-50"
                    >
                      <Sparkles className="w-3.5 h-3.5" />
                      {isLoading ? 'Enhancing...' : 'Enhance'}
                    </button>
                  </div>
                </div>

                <div className="flex flex-wrap items-center justify-between gap-4">
                   <div className="flex items-center gap-3">
                      <input 
                        type="file" 
                        ref={fileInputRef} 
                        onChange={handleFileUpload} 
                        className="hidden" 
                        accept="image/*"
                      />
                      <button 
                        onClick={() => fileInputRef.current?.click()}
                        className={`flex items-center gap-2 px-4 py-2 rounded-xl border-2 transition-all ${uploadedImage ? 'bg-green-500/10 border-green-500 text-green-400' : 'bg-slate-900 border-slate-800 hover:border-slate-700'}`}
                      >
                        <ImageIcon className="w-4 h-4" />
                        <span className="text-sm font-medium">{uploadedImage ? 'Change Image' : 'Add Image'}</span>
                      </button>

                      {uploadedImage && (
                        <div className="flex gap-2">
                          <button 
                            onClick={() => { setUploadedImage(null); setMode('text-to-image'); }}
                            className="p-2 rounded-xl bg-red-500/10 border-2 border-red-500/30 text-red-400 hover:bg-red-500/20"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                          <div className="flex items-center gap-2 bg-slate-900 border border-slate-800 px-3 py-1 rounded-xl">
                            <span className="text-xs text-slate-500">Mode:</span>
                            <select 
                              value={mode} 
                              onChange={(e) => setMode(e.target.value as GenerationMode)}
                              className="bg-transparent text-xs outline-none"
                            >
                              <option value="image-to-image">Img2Img</option>
                              <option value="inpainting">Inpainting</option>
                              <option value="outpainting">Outpainting</option>
                            </select>
                          </div>
                        </div>
                      )}
                   </div>

                   <button 
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className="gradient-border group"
                   >
                    <div className="flex items-center gap-2 px-8 py-3 group-hover:bg-transparent transition-colors">
                      {isLoading ? (
                        <RefreshCw className="w-5 h-5 animate-spin text-white" />
                      ) : (
                        <Sparkles className="w-5 h-5 text-white" />
                      )}
                      <span className="font-bold text-white">{isLoading ? 'Generating...' : 'Create Magic'}</span>
                    </div>
                   </button>
                </div>
              </div>

              {/* Status / Results */}
              <div className="min-h-[400px] flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-3xl p-12 bg-slate-900/20">
                {error && (
                  <div className="mb-6 p-4 bg-red-500/10 border border-red-500/30 rounded-xl flex items-center gap-3 text-red-400">
                    <AlertCircle className="w-5 h-5 flex-shrink-0" />
                    <p className="text-sm">{error}</p>
                  </div>
                )}

                {!isLoading && currentResult.length === 0 && !error && (
                  <div className="text-center space-y-4 max-w-sm">
                    <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-6">
                      <ImageIcon className="w-8 h-8 text-slate-600" />
                    </div>
                    <h3 className="text-xl font-bold text-slate-300">Ready to Dream?</h3>
                    <p className="text-slate-500 text-sm">Enter a prompt above and click generate to start creating amazing AI artwork.</p>
                  </div>
                )}

                {isLoading && (
                  <div className="text-center space-y-6 animate-pulse">
                    <div className="relative w-32 h-32 mx-auto">
                      <div className="absolute inset-0 border-4 border-blue-500/20 rounded-full"></div>
                      <div className="absolute inset-0 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                    </div>
                    <div>
                      <h3 className="text-lg font-bold text-blue-400">Brewing your masterpiece...</h3>
                      <p className="text-slate-500 text-sm mt-2">Thinking in pixels, dreaming in light.</p>
                    </div>
                  </div>
                )}

                {!isLoading && currentResult.length > 0 && (
                  <div className={`grid gap-6 w-full ${currentResult.length > 1 ? 'grid-cols-2' : 'grid-cols-1'}`}>
                    {currentResult.map((url, idx) => (
                      <div key={idx} className="group relative rounded-2xl overflow-hidden border-2 border-slate-800 bg-slate-900 shadow-2xl">
                        <img src={url} alt={`Result ${idx}`} className="w-full h-auto object-contain" />
                        <div className="absolute inset-x-0 bottom-0 p-4 bg-gradient-to-t from-black/90 to-transparent translate-y-full group-hover:translate-y-0 transition-transform flex items-center justify-center gap-3">
                          <button 
                            onClick={() => downloadImage(url)}
                            className="p-3 bg-white/10 hover:bg-white/20 rounded-full backdrop-blur-md transition-colors"
                            title="Download PNG"
                          >
                            <Download className="w-5 h-5" />
                          </button>
                          <button 
                            onClick={() => copyToClipboard(url)}
                            className="p-3 bg-white/10 hover:bg-white/20 rounded-full backdrop-blur-md transition-colors"
                            title="Copy to Clipboard"
                          >
                            <Copy className="w-5 h-5" />
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Recent Prompts */}
              {history.length > 0 && (
                <section className="space-y-4">
                  <div className="flex items-center gap-2 text-slate-500">
                    <Clock className="w-4 h-4" />
                    <h4 className="text-sm font-semibold uppercase tracking-wider">Recent Activity</h4>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {history.map((item, i) => (
                      <button 
                        key={i} 
                        onClick={() => setPrompt(item.prompt)}
                        className="px-4 py-2 bg-slate-900 border border-slate-800 rounded-full text-xs text-slate-400 hover:text-white hover:border-slate-600 transition-colors max-w-xs truncate"
                      >
                        {item.prompt}
                      </button>
                    ))}
                  </div>
                </section>
              )}
            </>
          ) : (
            /* Gallery Tab */
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
              {generatedImages.length === 0 ? (
                <div className="col-span-full py-20 text-center text-slate-500 space-y-4">
                   <div className="w-12 h-12 bg-slate-900 rounded-xl flex items-center justify-center mx-auto">
                      <Trash2 className="w-6 h-6" />
                   </div>
                   <p>Your creative vault is empty.</p>
                </div>
              ) : (
                generatedImages.map((img) => (
                  <div key={img.id} className="group relative aspect-square rounded-2xl overflow-hidden bg-slate-900 border border-slate-800 hover:border-blue-500 transition-all">
                    <img src={img.url} alt={img.prompt} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity p-4 flex flex-col justify-between">
                       <p className="text-[10px] line-clamp-3 font-medium text-slate-200">{img.prompt}</p>
                       <div className="flex gap-2">
                          <button onClick={() => downloadImage(img.url)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20"><Download className="w-3.5 h-3.5" /></button>
                          <button onClick={() => setPrompt(img.prompt)} className="p-2 bg-white/10 rounded-lg hover:bg-white/20"><RefreshCw className="w-3.5 h-3.5" /></button>
                       </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

export type AspectRatio = '1:1' | '3:4' | '4:3' | '16:9' | '9:16';
export type Resolution = '1K' | '2K' | '4K';
export type GenerationMode = 'text-to-image' | 'image-to-image' | 'inpainting' | 'outpainting';

export interface StylePreset {
  id: string;
  name: string;
  promptSuffix: string;
  previewUrl: string;
}

export interface GenerationSettings {
  aspectRatio: AspectRatio;
  resolution: Resolution;
  style: string;
  mood: string;
  lighting: string;
  colorTone: string;
  negativePrompt: string;
  seed: number | null;
  numImages: number;
  useProModel: boolean;
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  timestamp: number;
  settings: GenerationSettings;
  originalImage?: string; // For img2img/inpainting variations
}

export interface PromptHistoryItem {
  prompt: string;
  timestamp: number;
}

import { StylePreset } from './types';

export const STYLE_PRESETS: StylePreset[] = [
  { id: 'none', name: 'None', promptSuffix: '', previewUrl: 'https://picsum.photos/seed/style1/200' },
  { id: 'photo', name: 'Realistic Photo', promptSuffix: 'high resolution, photorealistic, 8k, detailed skin textures, cinematic lighting', previewUrl: 'https://picsum.photos/seed/photo/200' },
  { id: 'anime', name: 'Anime', promptSuffix: 'studio ghibli style, vibrant colors, detailed lineart, expressive characters', previewUrl: 'https://picsum.photos/seed/anime/200' },
  { id: 'cinematic', name: 'Cinematic', promptSuffix: 'hollywood movie still, dramatic lighting, anamorphic lens flares, high contrast', previewUrl: 'https://picsum.photos/seed/cinema/200' },
  { id: 'dslr', name: 'DSLR Portrait', promptSuffix: 'shallow depth of field, bokeh background, sharp focus, professional photography', previewUrl: 'https://picsum.photos/seed/dslr/200' },
  { id: 'oil', name: 'Oil Painting', promptSuffix: 'textured brushstrokes, thick paint, classic oil painting masterpiece, rich colors', previewUrl: 'https://picsum.photos/seed/oil/200' },
  { id: 'watercolor', name: 'Watercolor', promptSuffix: 'soft edges, bleeding colors, artistic paper texture, delicate washes', previewUrl: 'https://picsum.photos/seed/water/200' },
  { id: '3d', name: '3D Render', promptSuffix: 'octane render, unreal engine 5, raytracing, highly detailed, stylized 3D', previewUrl: 'https://picsum.photos/seed/3d/200' },
];

export const MOODS = ['Default', 'Vibrant', 'Dark', 'Soft', 'Dramatic', 'Ethereal', 'Gritty'];
export const LIGHTING = ['Default', 'Studio', 'Natural', 'Sunset', 'Neon', 'God Rays', 'Muted'];
export const COLOR_TONES = ['Default', 'Warm', 'Cool', 'Pastel', 'Monochrome', 'Vintage', 'High Saturation'];

export const ASPECT_RATIOS = [
  { label: '1:1 (4:4)', value: '1:1' as const, icon: 'Square' },
  { label: '4:3', value: '4:3' as const, icon: 'Monitor' },
  { label: '3:4', value: '3:4' as const, icon: 'Smartphone' },
  { label: '16:9', value: '16:9' as const, icon: 'Monitor' },
  { label: '9:16', value: '9:16' as const, icon: 'Smartphone' },
];

export const RESOLUTIONS = ['1K', '2K', '4K'] as const;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Settings2, 
  History, 
  Download, 
  Copy, 
  ChevronRight, 
  ChevronDown, 
  RefreshCw, 
  Trash2, 
  Layers,
  Eraser,
  Maximize2,
  Check,
  AlertCircle,
  Clock,
  Menu,
  X,
  Plus
} from 'lucide-react';
import { 
  GeneratedImage, 
  GenerationSettings, 
  AspectRatio, 
  Resolution, 
  GenerationMode,
  PromptHistoryItem
} from './types';
import { 
  STYLE_PRESETS, 
  MOODS, 
  LIGHTING, 
  COLOR_TONES, 
  ASPECT_RATIOS, 
  RESOLUTIONS 
} from './constants';
import { generateImage, enhancePrompt, translatePrompt } from './geminiService';

const App: React.FC = () => {
  // --- UI State ---
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isAdvancedMode, setAdvancedMode] = useState(false);
  const [activeTab, setActiveTab] = useState<'generate' | 'gallery'>('generate');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // --- Generation State ---
  const [prompt, setPrompt] = useState('');
  const [mode, setMode] = useState<GenerationMode>('text-to-image');
  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: '1:1',
    resolution: '1K',
    style: 'none',
    mood: 'Default',
    lighting: 'Default',
    colorTone: 'Default',
    negativePrompt: '',
    seed: null,
    numImages: 1,
    useProModel: false,
  });

  // --- Image Handling ---
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [maskImage, setMaskImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentResult, setCurrentResult] = useState<string[]>([]);
  const [history, setHistory] = useState<PromptHistoryItem[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load History from Local Storage
  useEffect(() => {
    const savedGallery = localStorage.getItem('dreamgen_gallery');
    if (savedGallery) setGeneratedImages(JSON.parse(savedGallery));

    const savedHistory = localStorage.getItem('dreamgen_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const saveToGallery = (urls: string[], currentPrompt: string) => {
    const newItems: GeneratedImage[] = urls.map(url => ({
      id: Math.random().toString(36).substr(2, 9),
      url,
      prompt: currentPrompt,
      timestamp: Date.now(),
      settings: { ...settings },
      originalImage: uploadedImage || undefined
    }));
    const updatedGallery = [...newItems, ...generatedImages].slice(0, 50);
    setGeneratedImages(updatedGallery);
    localStorage.setItem('dreamgen_gallery', JSON.stringify(updatedGallery));

    const newHistoryItem = { prompt: currentPrompt, timestamp: Date.now() };
    const updatedHistory = [newHistoryItem, ...history.filter(h => h.prompt !== currentPrompt)].slice(0, 10);
    setHistory(updatedHistory);
    localStorage.setItem('dreamgen_history', JSON.stringify(updatedHistory));
  };

  const handleEnhancePrompt = async () => {
    if (!prompt.trim()) return;
    setIsLoading(true);
    const enhanced = await enhancePrompt(prompt);
    setPrompt(enhanced);
    setIsLoading(false);
  };

  const handleGenerate = async () => {
    if (!prompt.trim() && !uploadedImage) {
      setError("Please enter a prompt or upload an image.");
      return;
    }

    // For Pro model, user must select their own API key
    if (settings.useProModel && typeof (window as any).aistudio !== 'undefined') {
      const hasKey = await (window as any).aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await (window as any).aistudio.openSelectKey();
        // Proceeding assumes key selection triggered successfully
      }
    }

    setIsLoading(true);
    setError(null);
    setCurrentResult([]);

    try {
      const translated = await translatePrompt(prompt);
      const results = await generateImage(translated, settings, mode, uploadedImage || undefined, maskImage || undefined);
      setCurrentResult(results);
      saveToGallery(results, prompt);
    } catch (err: any) {
      let errorMessage = err.message || "Generation failed. Please try again.";

      // If the request fails because the project is not found (often due to API key issues), prompt for key again.
      if (errorMessage.includes("Requested entity was not found.") && settings.useProModel) {
        errorMessage = "API key selection required for Pro models. Please try selecting a key from a paid project.";
        if (typeof (window as any).aistudio !== 'undefined') {
          await (window as any).aistudio.openSelectKey();
        }
      }

      setError(errorMessage);
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (readerEvent) => {
        setUploadedImage(readerEvent.target?.result as string);
        setMode('image-to-image');
      };
      reader.readAsDataURL(file);
    }
  };

  const downloadImage = (url: string, format: string = 'png') => {
    const link = document.createElement('a');
    link.href = url;
    link.download = `dreamgen-${Date.now()}.${format}`;
    link.click();
  };

  const copyToClipboard = async (url: string) => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      await navigator.clipboard.write([
        new ClipboardItem({ [blob.type]: blob })
      ]);
      alert("Image copied to clipboard!");
    } catch (err) {
      alert("Failed to copy image.");
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-950 text-slate-200">
      {/* Mobile Header */}
      <div className="lg:hidden fixed top-0 left-0 right-0 h-16 glass-panel z-50 flex items-center justify-between px-4">
        <div className="flex items-center gap-2">
          <Sparkles className="text-blue-500 w-6 h-6" />
          <span className="font-bold text-xl tracking-tight">DreamGen AI</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Sidebar Controls */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-80 glass-panel border-r border-slate-800 transition-transform duration-300 lg:relative lg:translate-x-0
        ${isMobileMenuOpen ? 'translate-x-0 pt-20' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="h-full flex flex-col p-6 space-y-8 overflow-y-auto">
          <div className="hidden lg:flex items-center gap-2 mb-4">
            <Sparkles className="text-blue-500 w-8 h-8" />
            <span className="font-bold text-2xl tracking-tight">DreamGen AI</span>
          </div>

          {/* Style Presets */}
          <section>
            <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Layers className="w-4 h-4" /> Style Presets
            </h3>
            <div className="grid grid-cols-2 gap-3">
              {STYLE_PRESETS.map((style) => (
                <button
                  key={style.id}
                  onClick={() => setSettings({ ...settings, style: style.id })}
                  className={`
                    group relative aspect-square rounded-xl overflow-hidden border-2 transition-all duration-200
                    ${settings.style === style.id ? 'border-blue-500 ring-2 ring-blue-500/20' : 'border-slate-800 hover:border-slate-700'}
                  `}
                >
                  <img src={style.previewUrl} alt={style.name} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent flex items-end p-2">
                    <span className="text-[10px] font-medium truncate w-full">{style.name}</span>
                  </div>
                  {settings.style === style.id && (
                    <div className="absolute top-1 right-1 bg-blue-500 rounded-full p-0.5">
                      <Check className="w-3 h-3 text-white" />
                    </div>
                  )}
                </button>
              ))}
            </div>
          </section>

          {/* Aspect Ratio */}
          <section>
            <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4">Aspect Ratio</h3>
            <div className="grid grid-cols-2 gap-2">
              {ASPECT_RATIOS.map((ratio) => (
                <button
                  key={ratio.value}
                  onClick={() => setSettings({ ...settings, aspectRatio: ratio.value })}
                  className={`
                    py-2 px-1 rounded-lg text-xs font-medium border transition-colors
                    ${settings.aspectRatio === ratio.value ? 'bg-blue-500/10 border-blue-500 text-blue-400' : 'bg-slate-900 border-slate-800 hover:border-slate-700'}
                  `}
                >
                  {ratio.label}
                </button>
              ))}
            </div>
          </section>

          {/* Model Selection */}
          <section>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Model Quality</h3>
              <div 
                className={`w-10 h-5 rounded-full p-1 cursor-pointer transition-colors ${settings.useProModel ? 'bg-purple-600' : 'bg-slate-700'}`}
                onClick={() => setSettings({ ...settings, useProModel: !settings.useProModel })}
              >
                <div className={`w-3 h-3 bg-white rounded-full transition-transform ${settings.useProModel ? 'translate-x-5' : 'translate-x-0'}`} />
              </div>
            </div>
            <div className="text-[10px] text-slate-500 mb-2 italic">
              {settings.useProModel ? 'Gemini 3 Pro: High quality, requires billing key' : 'Gemini 2.5 Flash: Fast & standard quality'}
            </div>
            {settings.useProModel && (
              <div className="grid grid-cols-3 gap-2 mt-2">
                {RESOLUTIONS.map((res) => (
                  <button
                    key={res}
                    onClick={() => setSettings({ ...settings, resolution: res })}
                    className={`
                      py-1 rounded-lg text-[10px] border transition-colors
                      ${settings.resolution === res ? 'bg-purple-500/10 border-purple-500 text-purple-400' : 'bg-slate-900 border-slate-800'}
                    `}
                  >
                    {res}
                  </button>
                ))}
              </div>
            )}
          </section>

          {/* Creative Tweaks */}
          <section className="space-y-4">
             <div className="flex flex-col gap-2">
                <label className="text-xs font-semibold text-slate-500">Mood</label>
                <select 
                  value={settings.mood}
                  onChange={(e) => setSettings({...settings, mood: e.target.value})}
                  className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                >
                  {MOODS.map(m => <option key={m} value={m}>{m}</option>)}
                </select>
             </div>
             <div className="flex flex-col gap-2">
                <label className="text-xs font-semibold text-slate-500">Lighting</label>
                <select 
                  value={settings.lighting}
                  onChange={(e) => setSettings({...settings, lighting: e.target.value})}
                  className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                >
                  {LIGHTING.map(l => <option key={l} value={l}>{l}</option>)}
                </select>
             </div>
          </section>

          {/* Advanced Mode Toggle */}
          <button 
            onClick={() => setAdvancedMode(!isAdvancedMode)}
            className="flex items-center justify-between text-xs font-semibold text-slate-500 hover:text-slate-300 py-2 border-t border-slate-800"
          >
            <span>Advanced Controls</span>
            {isAdvancedMode ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
          </button>

          {isAdvancedMode && (
            <div className="space-y-4 pt-2 animate-in slide-in-from-top-2 duration-300">
               <div className="flex flex-col gap-2">
                  <label className="text-xs font-semibold text-slate-500">Negative Prompt</label>
                  <textarea 
                    value={settings.negativePrompt}
                    onChange={(e) => setSettings({...settings, negativePrompt: e.target.value})}
                    placeholder="Avoid these elements..."
                    className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-xs h-20 resize-none focus:ring-1 focus:ring-red-500 outline-none"
                  />
               </div>
               <div className="flex items-center justify-between">
                  <label className="text-xs font-semibold text-slate-500">Batch Count</label>
                  <input 
                    type="number" min="1" max="4"
                    value={settings.numImages}
                    onChange={(e) => setSettings({...settings, numImages: parseInt(e.target.value)})}
                    className="w-16 bg-slate-900 border border-slate-800 rounded-lg p-1 text-xs text-center"
                  />
               </div>
            </div>
          )}
        </div>
      </aside>

      {/* Main Workspace */}
      <main className="flex-1 flex flex-col min-w-0 overflow-y-auto">
        <header className="p-4 lg:p-8 flex items-center justify-between border-b border-slate-900/50">
          <nav className="flex gap-8">
            <button 
              onClick={() => setActiveTab('generate')}
              className={`pb-2 text-sm font-semibold transition-colors border-b-2 ${activeTab === 'generate' ? 'text-blue-500 border-blue-500' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
            >
              Generate
            </button>
            <button 
              onClick={() => setActiveTab('gallery')}
              className={`pb-2 text-sm font-semibold transition-colors border-b-2 ${activeTab === 'gallery' ? 'text-blue-500 border-blue-500' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
            >
              Gallery
            </button>
          </nav>
        </header>

        <div className="flex-1 p-4 lg:p-8 max-w-6xl mx-auto w-full space-y-8">
          {activeTab === 'generate' ? (
            <>
