                            >
                              <option value="image-to-image">Img2Img</option>
                              <option value="inpainting">Inpainting</option>
                              <option value="outpainting">Outpainting</option>
                            </select>
                          </div>
                        </div>
                      )}
                   </div>

                   <button 
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className="gradient-border group"
                   >
