  id: string;
  name: string;
  promptSuffix: string;
  previewUrl: string;
}

export interface FeaturedPrompt {
  id: string;
  title: string;
  prompt: string;
  style: string;
  aspectRatio: AspectRatio;
  previewUrl: string;
}

export interface GenerationSettings {
  aspectRatio: AspectRatio;
  resolution: Resolution;
  style: string;
  mood: string;
  lighting: string;
  colorTone: string;
  negativePrompt: string;
  seed: number | null;
  numImages: number;
  useProModel: boolean;
  useSearch?: boolean;
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  timestamp: number;
  settings: GenerationSettings;
  originalImage?: string;
}

export interface PromptHistoryItem {
  prompt: string;
  timestamp: number;
}

