  const [activeTab, setActiveTab] = useState<'generate' | 'gallery'>('generate');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // --- Generation State ---
  const [prompt, setPrompt] = useState('');
  const [mode, setMode] = useState<GenerationMode>('text-to-image');
  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: '1:1',
    resolution: '1K',
    style: 'none',
    mood: 'Default',
    lighting: 'Default',
    colorTone: 'Default',
    negativePrompt: '',
    seed: null,
    numImages: 1,
    useProModel: false,
    useSearch: false
  });

  // --- Image Handling ---
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [maskImage, setMaskImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentResult, setCurrentResult] = useState<string[]>([]);
  const [history, setHistory] = useState<PromptHistoryItem[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load History from Local Storage
  useEffect(() => {
    const savedGallery = localStorage.getItem('dreamgen_gallery');
    if (savedGallery) setGeneratedImages(JSON.parse(savedGallery));

    const savedHistory = localStorage.getItem('dreamgen_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  const saveToGallery = (urls: string[], currentPrompt: string) => {
    const newItems: GeneratedImage[] = urls.map(url => ({
      id: Math.random().toString(36).substr(2, 9),
      url,
      prompt: currentPrompt,
      timestamp: Date.now(),
      settings: { ...settings },
      originalImage: uploadedImage || undefined
    }));
    const updatedGallery = [...newItems, ...generatedImages].slice(0, 100);
    setGeneratedImages(updatedGallery);
    localStorage.setItem('dreamgen_gallery', JSON.stringify(updatedGallery));

    const newHistoryItem = { prompt: currentPrompt, timestamp: Date.now() };
    const updatedHistory = [newHistoryItem, ...history.filter(h => h.prompt !== currentPrompt)].slice(0, 15);
    setHistory(updatedHistory);
    localStorage.setItem('dreamgen_history', JSON.stringify(updatedHistory));
  };

  const applyFeaturedPrompt = (item: FeaturedPrompt) => {
    setPrompt(item.prompt);
    setSettings(prev => ({
      ...prev,
      aspectRatio: item.aspectRatio,
      style: item.style
    }));
    setActiveTab('generate');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleEnhancePrompt = async () => {
    if (!prompt.trim()) return;
    setIsLoading(true);
    const enhanced = await enhancePrompt(prompt);
    setPrompt(enhanced);
    setIsLoading(false);
  };

  const handleGenerate = async () => {
    if (!prompt.trim() && !uploadedImage) {
      setError("Please describe your vision or upload an image.");
      return;
    }

    // Key Selection Flow for Pro Models
    if (settings.useProModel && typeof (window as any).aistudio !== 'undefined') {
      const hasKey = await (window as any).aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await (window as any).aistudio.openSelectKey();
      }
    }

    setIsLoading(true);
    setError(null);
    setCurrentResult([]);

    try {
      const translated = await translatePrompt(prompt);
      const results = await generateImage(translated, settings, mode, uploadedImage || undefined, maskImage || undefined);
      setCurrentResult(results);
      saveToGallery(results, prompt);
    } catch (err: any) {
      let errorMessage = err.message || "An unexpected error occurred.";

      if (errorMessage.includes("Requested entity was not found.") && settings.useProModel) {
        errorMessage = "A paid API key is required for Pro models. Please select a key from a project with billing enabled.";
        if (typeof (window as any).aistudio !== 'undefined') {
          await (window as any).aistudio.openSelectKey();
        }
      }
      setError(errorMessage);
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (readerEvent) => {
        setUploadedImage(readerEvent.target?.result as string);
        setMode('image-to-image');
      };
      reader.readAsDataURL(file);
    }
  };

  const downloadImage = (url: string) => {
    const link = document.createElement('a');
    link.href = url;
    link.download = `dreamgen-${Date.now()}.png`;
    link.click();
  };

  const copyToClipboard = async (url: string) => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      await navigator.clipboard.write([
        new ClipboardItem({ [blob.type]: blob })
      ]);
      alert("Copied to clipboard!");
    } catch (err) {
      alert("Failed to copy image.");
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-950 text-slate-200">
      {/* Mobile Top Bar */}
      <div className="lg:hidden fixed top-0 left-0 right-0 h-16 glass-panel z-50 flex items-center justify-between px-4">
        <div className="flex items-center gap-2">
          <Sparkles className="text-blue-500 w-6 h-6" />
          <span className="font-bold text-xl">DreamGen AI</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Sidebar Controls */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-80 glass-panel border-r border-slate-800 transition-transform duration-300 lg:relative lg:translate-x-0
        ${isMobileMenuOpen ? 'translate-x-0 pt-20' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="h-full flex flex-col p-6 space-y-8 overflow-y-auto">
          <div className="hidden lg:flex items-center gap-2 mb-4">
            <Sparkles className="text-blue-500 w-8 h-8" />
            <span className="font-bold text-2xl tracking-tighter">DreamGen AI</span>
          </div>

          {/* Style Presets */}
          <section>
            <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
              <Layers className="w-4 h-4" /> Artistic Style
            </h3>
            <div className="grid grid-cols-2 gap-2">
              {STYLE_PRESETS.map((style) => (
                <button
                  key={style.id}
                  onClick={() => setSettings({ ...settings, style: style.id })}
                  className={`
                    group relative aspect-video rounded-xl overflow-hidden border-2 transition-all
                    ${settings.style === style.id ? 'border-blue-500 scale-[1.02]' : 'border-slate-800 hover:border-slate-700'}
                  `}
                >
                  <img src={style.previewUrl} alt={style.name} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent flex items-end p-2">
                    <span className="text-[10px] font-bold uppercase tracking-tighter truncate w-full">{style.name}</span>
                  </div>
                  {settings.style === style.id && (
                    <div className="absolute top-1 right-1 bg-blue-500 rounded-full p-0.5">
                      <Check className="w-3 h-3 text-white" />
                    </div>
                  )}
                </button>
              ))}
            </div>
          </section>

          {/* Aspect Ratio */}
          <section>
            <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-4">Ratio</h3>
            <div className="grid grid-cols-3 gap-2">
              {ASPECT_RATIOS.map((ratio) => (
                <button
                  key={ratio.value}
                  onClick={() => setSettings({ ...settings, aspectRatio: ratio.value })}
                  className={`
                    py-2 rounded-lg text-xs font-bold border transition-all
                    ${settings.aspectRatio === ratio.value ? 'bg-blue-500/10 border-blue-500 text-blue-400' : 'bg-slate-900 border-slate-800 hover:border-slate-700'}
                  `}
                >
                  {ratio.label}
                </button>
              ))}
            </div>
          </section>

          {/* Model Selection */}
          <section>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest">Masterpiece Mode</h3>
              <div 
                className={`w-10 h-5 rounded-full p-1 cursor-pointer transition-colors ${settings.useProModel ? 'bg-purple-600' : 'bg-slate-700'}`}
                onClick={() => setSettings({ ...settings, useProModel: !settings.useProModel })}
              >
                <div className={`w-3 h-3 bg-white rounded-full transition-transform ${settings.useProModel ? 'translate-x-5' : 'translate-x-0'}`} />
              </div>
            </div>
            {settings.useProModel && (
              <div className="space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                <div className="grid grid-cols-3 gap-2">
                  {RESOLUTIONS.map((res) => (
                    <button
                      key={res}
                      onClick={() => setSettings({ ...settings, resolution: res })}
                      className={`
                        py-1 rounded-lg text-[10px] border font-bold transition-colors
                        ${settings.resolution === res ? 'bg-purple-500/10 border-purple-500 text-purple-400' : 'bg-slate-900 border-slate-800'}
                      `}
                    >
                      {res}
                    </button>
                  ))}
                </div>
                <div className="flex items-center justify-between p-2 bg-purple-500/5 rounded-lg border border-purple-500/20">
                  <span className="text-[10px] font-bold text-purple-400">Search Grounding</span>
                  <input 
                    type="checkbox"
                    checked={settings.useSearch}
                    onChange={(e) => setSettings({...settings, useSearch: e.target.checked})}
                    className="w-4 h-4 rounded bg-slate-900 border-slate-800 text-purple-500 focus:ring-0"
                  />
                </div>
              </div>
            )}
          </section>

          {/* Tweaks */}
          <section className="space-y-4">
             <div className="flex flex-col gap-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Mood</label>
                <select 
                  value={settings.mood}
                  onChange={(e) => setSettings({...settings, mood: e.target.value})}
                  className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-xs font-bold focus:ring-1 focus:ring-blue-500 outline-none"
                >
                  {MOODS.map(m => <option key={m} value={m}>{m}</option>)}
                </select>
             </div>
             <div className="flex flex-col gap-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Lighting</label>
                <select 
                  value={settings.lighting}
                  onChange={(e) => setSettings({...settings, lighting: e.target.value})}
                  className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-xs font-bold focus:ring-1 focus:ring-blue-500 outline-none"
                >
                  {LIGHTING.map(l => <option key={l} value={l}>{l}</option>)}
                </select>
             </div>
          </section>

          {/* Advanced Mode Toggle */}
          <button 
            onClick={() => setAdvancedMode(!isAdvancedMode)}
            className="flex items-center justify-between text-xs font-bold text-slate-500 hover:text-slate-300 py-2 border-t border-slate-800 transition-colors"
          >
            <span>Advanced Settings</span>
            {isAdvancedMode ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
          </button>

          {isAdvancedMode && (
            <div className="space-y-4 pt-2 animate-in slide-in-from-top-2 duration-300">
               <div className="flex flex-col gap-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Negative Prompt</label>
                  <textarea 
                    value={settings.negativePrompt}
                    onChange={(e) => setSettings({...settings, negativePrompt: e.target.value})}
                    placeholder="Exclude: distorted hands, blur..."
                    className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-xs h-20 resize-none focus:ring-1 focus:ring-red-500/50 outline-none"
                  />
               </div>
               <div className="flex items-center justify-between">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Batch size</label>
                  <input 
                    type="number" min="1" max="4"
                    value={settings.numImages}
                    onChange={(e) => setSettings({...settings, numImages: parseInt(e.target.value) || 1})}
                    className="w-16 bg-slate-900 border border-slate-800 rounded-lg p-1 text-xs text-center font-bold"
                  />
               </div>
            </div>
          )}
        </div>
      </aside>

      {/* Main Workspace */}
      <main className="flex-1 flex flex-col min-w-0 overflow-y-auto">
        <header className="p-4 lg:p-8 flex items-center justify-between border-b border-slate-900/50 bg-slate-950/80 backdrop-blur-md sticky top-0 z-30">
          <nav className="flex gap-10">
            <button 
              onClick={() => setActiveTab('generate')}
              className={`pb-2 text-sm font-black uppercase tracking-widest transition-all border-b-2 ${activeTab === 'generate' ? 'text-blue-500 border-blue-500' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
            >
              Creative Studio
            </button>
            <button 
              onClick={() => setActiveTab('gallery')}
              className={`pb-2 text-sm font-black uppercase tracking-widest transition-all border-b-2 ${activeTab === 'gallery' ? 'text-blue-500 border-blue-500' : 'text-slate-500 border-transparent hover:text-slate-300'}`}
            >
              The Vault
            </button>
          </nav>

          <div className="hidden sm:flex items-center gap-4">
             <div className="flex items-center gap-2 px-3 py-1.5 bg-blue-500/10 text-blue-400 rounded-full text-[10px] font-black uppercase">
                <Zap className="w-3 h-3" />
                <span>Unlimited Access</span>
             </div>
          </div>
        </header>

        <div className="flex-1 p-4 lg:p-12 max-w-6xl mx-auto w-full space-y-16">
          {activeTab === 'generate' ? (
            <>
              {/* Prompt Input Area */}
              <div className="space-y-6">
                <div className="relative group">
                  <div className="absolute -inset-1 bg-gradient-to-r from-blue-500 to-purple-600 rounded-3xl blur opacity-20 group-focus-within:opacity-40 transition duration-500"></div>
                  <textarea
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="Describe your masterpiece here..."
                    className="relative w-full h-44 bg-slate-900/90 border-2 border-slate-800 rounded-3xl p-8 text-xl focus:border-blue-500 outline-none resize-none transition-all pr-48 placeholder:text-slate-700"
                  />
                  <div className="absolute bottom-6 right-6 flex gap-2">
                    <button 
                      onClick={handleEnhancePrompt}
                      disabled={isLoading}
                      className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 rounded-2xl text-[10px] font-black uppercase transition-all disabled:opacity-50 border border-slate-700"
                    >
                      <Sparkles className="w-3.5 h-3.5 text-blue-400" />
                      {isLoading ? 'Processing...' : 'Enhance'}
                    </button>
                  </div>
                </div>

                <div className="flex flex-wrap items-center justify-between gap-6">
                   <div className="flex items-center gap-4">
                      <input 
                        type="file" 
                        ref={fileInputRef} 
                        onChange={handleFileUpload} 
                        className="hidden" 
                        accept="image/*"
                      />
                      <button 
                        onClick={() => fileInputRef.current?.click()}
                        className={`flex items-center gap-2 px-6 py-4 rounded-2xl border-2 transition-all ${uploadedImage ? 'bg-green-500/10 border-green-500 text-green-400' : 'bg-slate-900 border-slate-800 hover:border-slate-700'}`}
                      >
                        <ImageIcon className="w-5 h-5" />
                        <span className="text-sm font-black uppercase tracking-widest">{uploadedImage ? 'Update Base' : 'Base Image'}</span>
                      </button>

                      {uploadedImage && (
                        <div className="flex gap-2">
                          <button 
                            onClick={() => { setUploadedImage(null); setMode('text-to-image'); }}
                            className="p-4 rounded-2xl bg-red-500/10 border-2 border-red-500/30 text-red-400 hover:bg-red-500/20 transition-all"
                          >
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </div>
                      )}
                   </div>

                   <button 
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className="gradient-border group min-w-[220px]"
                   >
                    <div className="flex items-center justify-center gap-3 px-10 py-5 group-hover:bg-transparent transition-all">
                      {isLoading ? (
                        <RefreshCw className="w-6 h-6 animate-spin text-white" />
                      ) : (
                        <Sparkles className="w-6 h-6 text-white" />
                      )}
                      <span className="font-black text-xl text-white uppercase tracking-tighter">{isLoading ? 'Baking...' : 'Create'}</span>
                    </div>
                   </button>
                </div>
              </div>

              {/* Inspiration Section */}
              {!isLoading && currentResult.length === 0 && (
                <section className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
                  <div className="flex items-center gap-4">
                    <Star className="w-8 h-8 text-yellow-500 fill-yellow-500" />
                    <h2 className="text-3xl font-black uppercase tracking-tighter">Studio Inspiration</h2>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                     {FEATURED_PROMPTS.map((item) => (
                       <div 
                        key={item.id} 
                        className="group relative rounded-[2.5rem] overflow-hidden bg-slate-900 border border-slate-800 hover:border-blue-500/50 transition-all cursor-pointer h-72 shadow-2xl"
                        onClick={() => applyFeaturedPrompt(item)}
                       >
                         <img src={item.previewUrl} alt={item.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000 opacity-60 group-hover:opacity-100" />
                         <div className="absolute inset-0 p-8 flex flex-col justify-end bg-gradient-to-t from-black/90 via-black/20 to-transparent">
                            <h3 className="text-2xl font-black text-white mb-2 leading-none">{item.title}</h3>
                            <p className="text-xs text-slate-400 font-medium mb-6 line-clamp-2 italic">"{item.prompt}"</p>
                            <div className="flex items-center gap-3">
                               <span className="px-3 py-1 bg-blue-500/20 text-blue-400 text-[10px] font-black uppercase rounded-lg border border-blue-500/30">Use Template</span>
                               <span className="px-3 py-1 bg-white/5 text-white text-[10px] font-black uppercase rounded-lg border border-white/5">{item.aspectRatio}</span>
                            </div>
                         </div>
                       </div>
                     ))}
                  </div>
                </section>
              )}

              {/* Status / Results */}
              <div className={`min-h-[500px] flex flex-col items-center justify-center border-2 border-dashed border-slate-900 rounded-[3rem] p-6 lg:p-12 transition-all ${isLoading || currentResult.length > 0 ? 'bg-slate-900/10' : 'bg-transparent'}`}>
                {error && (
                  <div className="mb-8 p-6 bg-red-500/10 border border-red-500/30 rounded-3xl flex items-center gap-4 text-red-400 max-w-xl animate-in zoom-in duration-300">
                    <AlertCircle className="w-8 h-8 flex-shrink-0" />
                    <div>
                       <p className="font-black uppercase tracking-widest text-xs mb-1">System Error</p>
                       <p className="text-sm font-medium">{error}</p>
                    </div>
                  </div>
                )}

                {isLoading && (
                  <div className="text-center space-y-10">
                    <div className="relative w-48 h-48 mx-auto">
                      <div className="absolute inset-0 border-[8px] border-blue-500/10 rounded-full"></div>
                      <div className="absolute inset-0 border-[8px] border-blue-500 border-t-transparent border-r-transparent rounded-full animate-spin"></div>
                      <div className="absolute inset-6 border-[8px] border-purple-500/10 rounded-full"></div>
                      <div className="absolute inset-6 border-[8px] border-purple-500 border-b-transparent border-l-transparent animate-[spin_1.5s_linear_infinite_reverse] rounded-full"></div>
                      <div className="absolute inset-0 flex items-center justify-center">
                        <Sparkles className="w-10 h-10 text-blue-400 animate-pulse" />
                      </div>
                    </div>
                    <div className="space-y-2">
                      <h3 className="text-2xl font-black text-white uppercase tracking-widest">Generating Masterpiece</h3>
                      <p className="text-slate-500 text-sm font-bold animate-pulse italic">Brewing pixels from pure imagination...</p>
                    </div>
                  </div>
                )}

                {!isLoading && currentResult.length > 0 && (
                  <div className={`grid gap-10 w-full max-w-5xl ${currentResult.length > 1 ? 'grid-cols-2' : 'grid-cols-1'}`}>
                    {currentResult.map((url, idx) => (
                      <div key={idx} className="group relative rounded-[2.5rem] overflow-hidden bg-slate-900 border border-slate-800 shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-700">
                        <img src={url} alt={`Masterpiece ${idx}`} className="w-full h-auto object-contain select-none" />
                        {/* 
                            Clean Overlay: Removed branding text/watermarks per user request. 
                            Now only provides high-utility action buttons.
                        */}
                        <div className="absolute inset-x-0 bottom-0 p-8 bg-gradient-to-t from-black/95 via-black/50 to-transparent translate-y-full group-hover:translate-y-0 transition-all duration-500 flex items-center justify-end backdrop-blur-sm">
                           <div className="flex gap-4">
                              <button 
                                onClick={() => downloadImage(url)}
                                className="p-4 bg-white/10 hover:bg-blue-600 hover:text-white rounded-2xl transition-all border border-white/5"
                                title="Download"
                              >
                                <Download className="w-5 h-5" />
                              </button>
                              <button 
                                onClick={() => copyToClipboard(url)}
                                className="p-4 bg-white/10 hover:bg-blue-600 hover:text-white rounded-2xl transition-all border border-white/5"
                                title="Copy"
                              >
                                <Copy className="w-5 h-5" />
                              </button>
                           </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* History */}
              {history.length > 0 && (
                <section className="space-y-6">
                  <div className="flex items-center gap-3 text-slate-500">
                    <Clock className="w-5 h-5" />
                    <h4 className="text-xs font-black uppercase tracking-widest">Recent Activity Log</h4>
                  </div>
                  <div className="flex flex-wrap gap-3">
                    {history.map((item, i) => (
                      <button 
                        key={i} 
                        onClick={() => setPrompt(item.prompt)}
                        className="px-6 py-3 bg-slate-900 border border-slate-800 rounded-2xl text-xs font-bold text-slate-400 hover:text-white hover:border-slate-600 transition-all max-w-xs truncate"
                      >
                        {item.prompt}
                      </button>
                    ))}
                  </div>
                </section>
              )}
            </>
          ) : (
            /* Gallery Tab */
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-10">
              {generatedImages.length === 0 ? (
                <div className="col-span-full py-40 text-center text-slate-500 space-y-8">
                   <div className="w-24 h-24 bg-slate-900 rounded-[2.5rem] flex items-center justify-center mx-auto shadow-inner border border-slate-800">
                      <ImageIcon className="w-10 h-10 text-slate-800" />
                   </div>
                   <div className="space-y-2">
                      <h2 className="text-2xl font-black text-slate-400 uppercase tracking-tighter">Your Creative Vault is empty</h2>
                      <p className="text-sm font-bold italic">Start generating to build your collection of AI-powered art.</p>
                   </div>
                   <button onClick={() => setActiveTab('generate')} className="px-10 py-4 bg-blue-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/20">Back to Studio</button>
                </div>
              ) : (
                generatedImages.map((img) => (
                  <div key={img.id} className="group relative aspect-square rounded-[2.5rem] overflow-hidden bg-slate-900 border border-slate-800 hover:border-blue-500/50 transition-all animate-in zoom-in duration-500 shadow-2xl">
                    <img src={img.url} alt={img.prompt} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/80 opacity-0 group-hover:opacity-100 transition-all p-8 flex flex-col justify-between backdrop-blur-md">
