                          <button onClick={() => { setPrompt(img.prompt); setActiveTab('generate'); }} className="p-4 bg-white/10 rounded-2xl hover:bg-blue-600 text-white transition-all border border-white/5"><RefreshCw className="w-5 h-5" /></button>
                       </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

