  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [hasKey, setHasKey] = useState<boolean>(true);

  // --- Generation State ---
  const [prompt, setPrompt] = useState('');
  const [mode, setMode] = useState<GenerationMode>('text-to-image');
  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: '1:1',
    resolution: '1K',
    style: 'none',
    mood: 'Default',
    lighting: 'Default',
    colorTone: 'Default',
    negativePrompt: '',
    seed: null,
    numImages: 1,
    useProModel: false,
    useSearch: false
  });

  // --- Image Handling ---
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [maskImage, setMaskImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentResult, setCurrentResult] = useState<string[]>([]);
  const [history, setHistory] = useState<PromptHistoryItem[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load History from Local Storage & Check Key
  useEffect(() => {
    const savedGallery = localStorage.getItem('dreamgen_gallery');
    if (savedGallery) setGeneratedImages(JSON.parse(savedGallery));

    const savedHistory = localStorage.getItem('dreamgen_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    checkKey();
  }, []);

  const checkKey = async () => {
    if (typeof (window as any).aistudio !== 'undefined') {
      const selected = await (window as any).aistudio.hasSelectedApiKey();
      setHasKey(selected || !!process.env.API_KEY);
    } else {
      setHasKey(!!process.env.API_KEY);
    }
  };

  const handleOpenKey = async () => {
    if (typeof (window as any).aistudio !== 'undefined') {
      await (window as any).aistudio.openSelectKey();
      setHasKey(true); // Assume success per instructions
      setError(null);
    }
  };

  const saveToGallery = (urls: string[], currentPrompt: string) => {
    const newItems: GeneratedImage[] = urls.map(url => ({
      id: Math.random().toString(36).substr(2, 9),
      url,
      prompt: currentPrompt,
      timestamp: Date.now(),
      settings: { ...settings },
      originalImage: uploadedImage || undefined
    }));
    const updatedGallery = [...newItems, ...generatedImages].slice(0, 100);
    setGeneratedImages(updatedGallery);
    localStorage.setItem('dreamgen_gallery', JSON.stringify(updatedGallery));

    const newHistoryItem = { prompt: currentPrompt, timestamp: Date.now() };
    const updatedHistory = [newHistoryItem, ...history.filter(h => h.prompt !== currentPrompt)].slice(0, 15);
    setHistory(updatedHistory);
    localStorage.setItem('dreamgen_history', JSON.stringify(updatedHistory));
  };

  const applyFeaturedPrompt = (item: FeaturedPrompt) => {
    setPrompt(item.prompt);
    setSettings(prev => ({
      ...prev,
      aspectRatio: item.aspectRatio,
      style: item.style
    }));
    setActiveTab('generate');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleEnhancePrompt = async () => {
    if (!prompt.trim()) return;
    setIsLoading(true);
    const enhanced = await enhancePrompt(prompt);
    setPrompt(enhanced);
    setIsLoading(false);
  };

  const handleGenerate = async () => {
    if (!prompt.trim() && !uploadedImage) {
      setError("Please describe your vision or upload an image.");
      return;
    }

    // Key selection check
    if (!process.env.API_KEY && typeof (window as any).aistudio !== 'undefined') {
       const keyCheck = await (window as any).aistudio.hasSelectedApiKey();
       if (!keyCheck) {
          await (window as any).aistudio.openSelectKey();
          setHasKey(true);
       }
    }

    setIsLoading(true);
    setError(null);
    // Note: We intentionally don't clear currentResult so previous image stays visible.

    try {
      const translated = await translatePrompt(prompt);
      const results = await generateImage(translated, settings, mode, uploadedImage || undefined, maskImage || undefined);
      setCurrentResult(results);
      saveToGallery(results, prompt);
    } catch (err: any) {
      let errorMessage = err.message || "An unexpected error occurred.";
      if (errorMessage.toLowerCase().includes("api key") || errorMessage.includes("Requested entity was not found")) {
        setHasKey(false);
        errorMessage = "API key issue detected. Please click 'Select API Key' to continue.";
        if (typeof (window as any).aistudio !== 'undefined') {
           await (window as any).aistudio.openSelectKey();
        }
      }
      setError(errorMessage);
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (readerEvent) => {
        setUploadedImage(readerEvent.target?.result as string);
        setMode('image-to-image');
      };
      reader.readAsDataURL(file);
    }
  };

