const App: React.FC = () => {
  // --- UI State ---
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isAdvancedMode, setAdvancedMode] = useState(false);
  const [activeTab, setActiveTab] = useState<'generate' | 'gallery'>('generate');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isKeyValid, setIsKeyValid] = useState<boolean>(true);

  // --- Generation State ---
  const [prompt, setPrompt] = useState('');
  const [mode, setMode] = useState<GenerationMode>('text-to-image');
  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: '1:1',
    resolution: '1K',
    style: 'none',
    mood: 'Default',
    lighting: 'Default',
    colorTone: 'Default',
    negativePrompt: '',
    seed: null,
    numImages: 1,
    useProModel: false,
    useSearch: false
  });

  // --- Image Handling ---
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [maskImage, setMaskImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentResult, setCurrentResult] = useState<string[]>([]);
  const [history, setHistory] = useState<PromptHistoryItem[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedGallery = localStorage.getItem('dreamgen_gallery');
    if (savedGallery) setGeneratedImages(JSON.parse(savedGallery));

    const savedHistory = localStorage.getItem('dreamgen_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    checkInitialKey();
  }, []);

  const checkInitialKey = async () => {
    if (typeof (window as any).aistudio !== 'undefined') {
      const selected = await (window as any).aistudio.hasSelectedApiKey();
      setIsKeyValid(selected || !!process.env.API_KEY);
    } else {
      setIsKeyValid(!!process.env.API_KEY);
    }
  };

  const handleSelectKey = async () => {
    if (typeof (window as any).aistudio !== 'undefined') {
      await (window as any).aistudio.openSelectKey();
      setIsKeyValid(true);
      setError(null);
    }
  };

  const saveToGallery = (urls: string[], currentPrompt: string) => {
    const newItems: GeneratedImage[] = urls.map(url => ({
      id: Math.random().toString(36).substr(2, 9),
      url,
      prompt: currentPrompt,
      timestamp: Date.now(),
      settings: { ...settings },
      originalImage: uploadedImage || undefined
    }));
    const updatedGallery = [...newItems, ...generatedImages].slice(0, 100);
    setGeneratedImages(updatedGallery);
    localStorage.setItem('dreamgen_gallery', JSON.stringify(updatedGallery));

    const newHistoryItem = { prompt: currentPrompt, timestamp: Date.now() };
    const updatedHistory = [newHistoryItem, ...history.filter(h => h.prompt !== currentPrompt)].slice(0, 15);
    setHistory(updatedHistory);
    localStorage.setItem('dreamgen_history', JSON.stringify(updatedHistory));
  };

  const applyFeaturedPrompt = (item: FeaturedPrompt) => {
    setPrompt(item.prompt);
    setSettings(prev => ({
      ...prev,
      aspectRatio: item.aspectRatio,
      style: item.style
    }));
    setActiveTab('generate');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleEnhancePrompt = async () => {
    if (!prompt.trim()) return;
    setIsLoading(true);
    const enhanced = await enhancePrompt(prompt);
    setPrompt(enhanced);
    setIsLoading(false);
  };

  const handleGenerate = async () => {
    if (!prompt.trim() && !uploadedImage) {
      setError("Please enter a prompt or upload an image.");
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const translated = await translatePrompt(prompt);
      const results = await generateImage(translated, settings, mode, uploadedImage || undefined, maskImage || undefined);
      setCurrentResult(results);
      saveToGallery(results, prompt);
      setIsKeyValid(true);
    } catch (err: any) {
      const msg = err.message || "";
      console.error("Generation Error:", err);

      if (msg === "API_KEY_MISSING") {
        setIsKeyValid(false);
        setError("API Key is required to generate images. Please select a key.");
        await handleSelectKey();
      } else if (msg === "MODEL_NOT_FOUND") {
        setIsKeyValid(false);
        setError(settings.useProModel 
          ? "Masterpiece Mode (Pro) requires a PAID API Key. Please select a key from a project with billing enabled."
          : "The selected model was not found. Please re-select your API key.");
        await handleSelectKey();
      } else {
        setError(msg || "Generation failed. Please try again.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (readerEvent) => {
        setUploadedImage(readerEvent.target?.result as string);
        setMode('image-to-image');
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-950 text-slate-200">
      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-80 glass-panel border-r border-slate-800 transition-transform duration-300 lg:relative lg:translate-x-0
        ${isMobileMenuOpen ? 'translate-x-0 pt-20' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="h-full flex flex-col p-6 space-y-8 overflow-y-auto">
          <div className="flex items-center gap-3 mb-2">
            <Sparkles className="text-blue-500 w-8 h-8" />
            <span className="font-bold text-2xl tracking-tighter">DreamGen AI</span>
          </div>

          {!isKeyValid && (
            <button 
              onClick={handleSelectKey}
              className="w-full flex items-center justify-center gap-2 p-4 bg-red-500/10 border border-red-500/50 rounded-2xl text-red-400 text-xs font-black uppercase tracking-widest hover:bg-red-500/20 transition-all animate-pulse"
            >
              <Key className="w-4 h-4" />
              Activate API Key
            </button>
          )}

          {/* Model Toggle */}
          <section className="p-4 bg-slate-900/50 rounded-2xl border border-slate-800">
            <div className="flex items-center justify-between mb-2">
              <div className="flex flex-col">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Masterpiece Mode</h3>
                <span className="text-[9px] text-purple-400 font-bold uppercase">Requires Billing</span>
              </div>
              <div 
                className={`w-10 h-5 rounded-full p-1 cursor-pointer transition-colors ${settings.useProModel ? 'bg-purple-600' : 'bg-slate-700'}`}
                onClick={() => setSettings({ ...settings, useProModel: !settings.useProModel })}
              >
                <div className={`w-3 h-3 bg-white rounded-full transition-transform ${settings.useProModel ? 'translate-x-5' : 'translate-x-0'}`} />
              </div>
            </div>
          </section>

          {/* Style Presets */}
          <section>
            <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
              <Layers className="w-4 h-4" /> Artistic Style
            </h3>
            <div className="grid grid-cols-2 gap-2">
              {STYLE_PRESETS.map((style) => (
                <button
                  key={style.id}
                  onClick={() => setSettings({ ...settings, style: style.id })}
                  className={`
                    group relative aspect-video rounded-xl overflow-hidden border-2 transition-all
                    ${settings.style === style.id ? 'border-blue-500 scale-[1.02]' : 'border-slate-800 hover:border-slate-700'}
                  `}
                >
                  <img src={style.previewUrl} alt={style.name} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent flex items-end p-2">
                    <span className="text-[10px] font-bold uppercase tracking-tighter truncate w-full">{style.name}</span>
                  </div>
                  {settings.style === style.id && <div className="absolute top-1 right-1 bg-blue-500 rounded-full p-0.5"><Check className="w-3 h-3 text-white" /></div>}
                </button>
              ))}
            </div>
          </section>

          {/* Ratio Selector */}
          <section>
            <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-4">Aspect Ratio</h3>
            <div className="grid grid-cols-3 gap-2">
              {ASPECT_RATIOS.map((ratio) => (
                <button
                  key={ratio.value}
                  onClick={() => setSettings({ ...settings, aspectRatio: ratio.value })}
                  className={`
                    py-2 rounded-lg text-xs font-bold border transition-all
                    ${settings.aspectRatio === ratio.value ? 'bg-blue-500/10 border-blue-500 text-blue-400' : 'bg-slate-900 border-slate-800 hover:border-slate-700'}
                  `}
                >
                  {ratio.label}
                </button>
              ))}
            </div>
          </section>

          {/* Tweak Sliders */}
          <section className="space-y-4">
             <div className="flex flex-col gap-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Mood</label>
                <select 
                  value={settings.mood}
                  onChange={(e) => setSettings({...settings, mood: e.target.value})}
                  className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-xs font-bold focus:ring-1 focus:ring-blue-500 outline-none"
                >
                  {MOODS.map(m => <option key={m} value={m}>{m}</option>)}
                </select>
             </div>
             <div className="flex flex-col gap-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Lighting</label>
                <select 
                  value={settings.lighting}
                  onChange={(e) => setSettings({...settings, lighting: e.target.value})}
                  className="bg-slate-900 border border-slate-800 rounded-lg p-2 text-xs font-bold focus:ring-1 focus:ring-blue-500 outline-none"
                >
                  {LIGHTING.map(l => <option key={l} value={l}>{l}</option>)}
                </select>
             </div>
          </section>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 overflow-y-auto">
        <header className="p-4 lg:p-8 flex items-center justify-between glass-panel sticky top-0 z-30">
          <nav className="flex gap-8">
            <button onClick={() => setActiveTab('generate')} className={`text-sm font-black uppercase tracking-widest transition-all ${activeTab === 'generate' ? 'text-blue-500' : 'text-slate-500'}`}>Studio</button>
            <button onClick={() => setActiveTab('gallery')} className={`text-sm font-black uppercase tracking-widest transition-all ${activeTab === 'gallery' ? 'text-blue-500' : 'text-slate-500'}`}>Vault</button>
          </nav>
          <button className="lg:hidden" onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}><Menu /></button>
        </header>

        <div className="flex-1 p-4 lg:p-12 max-w-6xl mx-auto w-full space-y-12">
          {activeTab === 'generate' ? (
            <>
              {/* Input Section */}
              <div className="space-y-6">
                <div className="relative">
                  <textarea
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="An astronaut riding a glowing horse through a nebula..."
                    className="w-full h-44 bg-slate-900/80 border-2 border-slate-800 rounded-3xl p-8 text-xl focus:border-blue-500 outline-none resize-none transition-all"
                  />
                  <button 
                    onClick={handleEnhancePrompt}
                    disabled={isLoading}
                    className="absolute bottom-6 right-6 flex items-center gap-2 px-4 py-2 bg-slate-800 text-blue-400 rounded-xl text-[10px] font-black uppercase border border-slate-700 hover:bg-slate-700 transition-all"
                  >
                    <Sparkles className="w-3 h-3" /> Enhance
                  </button>
                </div>

                <div className="flex flex-wrap items-center justify-between gap-6">
                  <div className="flex items-center gap-4">
                    <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-6 py-4 bg-slate-900 border border-slate-800 rounded-2xl text-sm font-black uppercase hover:border-slate-600 transition-all">
                      <ImageIcon className="w-5 h-5" /> {uploadedImage ? 'Swap Base' : 'Base Image'}
                    </button>
                    <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileUpload} accept="image/*" />
                    {uploadedImage && <button onClick={() => setUploadedImage(null)} className="p-4 text-red-400 bg-red-400/10 rounded-2xl"><Trash2 /></button>}
                  </div>

                  <button onClick={handleGenerate} disabled={isLoading} className="gradient-border group px-12 py-5 rounded-2xl hover:opacity-90 transition-all">
                    <div className="flex items-center gap-3">
                      {isLoading ? <RefreshCw className="animate-spin" /> : <Sparkles />}
                      <span className="font-black text-xl uppercase tracking-tighter">Create</span>
                    </div>
                  </button>
                </div>
              </div>

              {/* Status Display */}
              <div className="min-h-[500px] flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-[3rem] p-8 relative overflow-hidden">
                {error && (
                  <div className="max-w-xl w-full p-8 bg-red-500/10 border border-red-500/30 rounded-3xl flex items-start gap-6 animate-in zoom-in">
                    <AlertCircle className="w-8 h-8 text-red-400 flex-shrink-0" />
                    <div className="space-y-4">
                      <h4 className="font-black uppercase tracking-widest text-red-400">System Alert</h4>
                      <p className="text-sm font-medium text-slate-300 leading-relaxed">{error}</p>
                      {!isKeyValid && (
                        <button onClick={handleSelectKey} className="flex items-center gap-2 px-6 py-3 bg-red-500 text-white rounded-xl text-xs font-black uppercase shadow-xl shadow-red-500/20">
                          <Key className="w-4 h-4" /> Select Valid Key
                        </button>
                      )}
                    </div>
                  </div>
                )}

                {isLoading && currentResult.length === 0 && (
                  <div className="text-center space-y-6 animate-pulse">
                    <div className="w-24 h-24 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto" />
                    <h3 className="text-2xl font-black uppercase tracking-widest">Baking Masterpiece...</h3>
                  </div>
                )}

                {currentResult.length > 0 && (
                  <div className="relative w-full max-w-5xl">
                    <div className={`grid gap-8 ${currentResult.length > 1 ? 'grid-cols-2' : 'grid-cols-1'}`}>
                      {currentResult.map((url, idx) => (
                        <div key={idx} className="group relative rounded-3xl overflow-hidden shadow-2xl border border-slate-800">
                          <img 
                            src={url} 
                            alt="Generated" 
                            className={`w-full h-auto object-contain transition-all duration-700 ${isLoading ? 'blur-2xl opacity-40 grayscale' : ''}`}
                          />
                          <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center gap-4">
                            <button onClick={() => window.open(url)} className="p-4 bg-white/10 rounded-2xl hover:bg-blue-600 transition-all"><ExternalLink /></button>
                            <button onClick={() => { const a = document.createElement('a'); a.href = url; a.download = 'dreamgen.png'; a.click(); }} className="p-4 bg-white/10 rounded-2xl hover:bg-blue-600 transition-all"><Download /></button>
                          </div>
                        </div>
                      ))}
                    </div>

                    {isLoading && (
                      <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-950/60 backdrop-blur-md rounded-3xl animate-in fade-in">
                        <RefreshCw className="w-12 h-12 animate-spin text-blue-500 mb-4" />
                        <span className="font-black uppercase tracking-widest text-blue-400">Updating Canvas...</span>
                      </div>
                    )}
                  </div>
                )}

                {!isLoading && currentResult.length === 0 && !error && (
                  <div className="text-center text-slate-600 italic">
                    <Sparkles className="w-16 h-16 mx-auto mb-4 opacity-20" />
                    <p>Enter a prompt and click create to see the magic happen.</p>
                  </div>
                )}
              </div>
            </>
          ) : (
            /* Gallery */
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-8">
              {generatedImages.map(img => (
                <div key={img.id} className="group relative aspect-square rounded-3xl overflow-hidden border border-slate-800">
                  <img src={img.url} className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-black/80 opacity-0 group-hover:opacity-100 transition-all p-6 flex flex-col justify-end backdrop-blur-sm">
                    <p className="text-[10px] font-bold line-clamp-3 mb-4 italic">"{img.prompt}"</p>
                    <button onClick={() => { setPrompt(img.prompt); setActiveTab('generate'); }} className="w-full py-3 bg-blue-600 text-white rounded-xl text-[10px] font-black uppercase">Re-use Prompt</button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Download, 
  RefreshCw, 
  Trash2, 
  Layers,
  Check,
  AlertCircle,
  Menu,
  X,
  Star,
  ExternalLink,
  Key,
  ShieldCheck,
  Info
} from 'lucide-react';
import { 
  GeneratedImage, 
  GenerationSettings, 
  AspectRatio, 
  Resolution, 
  GenerationMode,
  PromptHistoryItem,
  FeaturedPrompt
} from './types';
import { 
  STYLE_PRESETS, 
  MOODS, 
  LIGHTING, 
  ASPECT_RATIOS, 
  RESOLUTIONS,
  FEATURED_PROMPTS
} from './constants';
import { generateImage, enhancePrompt, translatePrompt } from './geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'generate' | 'gallery'>('generate');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isKeySelected, setIsKeySelected] = useState<boolean>(true);

  const [prompt, setPrompt] = useState('');
  const [mode, setMode] = useState<GenerationMode>('text-to-image');
  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: '1:1',
    resolution: '1K',
    style: 'none',
    mood: 'Default',
    lighting: 'Default',
    colorTone: 'Default',
    negativePrompt: '',
    seed: null,
    numImages: 1,
    useProModel: false,
    useSearch: false
  });

  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentResult, setCurrentResult] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    checkKey();
    const saved = localStorage.getItem('dreamgen_gallery');
    if (saved) setGeneratedImages(JSON.parse(saved));
  }, []);

  const checkKey = async () => {
    if (typeof (window as any).aistudio !== 'undefined') {
      const selected = await (window as any).aistudio.hasSelectedApiKey();
      setIsKeySelected(selected || !!process.env.API_KEY);
    }
  };

  const handleSelectKey = async () => {
    if (typeof (window as any).aistudio !== 'undefined') {
      await (window as any).aistudio.openSelectKey();
      setIsKeySelected(true);
      setError(null);
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim() && !uploadedImage) {
      setError("Please describe what you want to create.");
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const translated = await translatePrompt(prompt);
      const results = await generateImage(translated, settings, mode, uploadedImage || undefined);
      setCurrentResult(results);

      const newItems = results.map(url => ({
        id: Math.random().toString(36).substr(2, 9),
        url,
        prompt,
        timestamp: Date.now(),
        settings: { ...settings }
      }));
      setGeneratedImages(prev => [...newItems, ...prev]);
      localStorage.setItem('dreamgen_gallery', JSON.stringify([...newItems, ...generatedImages]));
      setIsKeySelected(true);
    } catch (err: any) {
      const msg = err.message || "";
      if (msg === "API_KEY_MISSING" || msg.includes("API Key must be set")) {
        setIsKeySelected(false);
        setError("API Key Missing: Please click the 'Select API Key' button below to continue.");
      } else if (msg === "MODEL_NOT_FOUND") {
        setError("Billing Required: Masterpiece Mode (Gemini Pro) requires an API key from a project with billing enabled.");
      } else {
        setError(msg || "Generation failed. Try a simpler prompt or check your connection.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setUploadedImage(ev.target?.result as string);
        setMode('image-to-image');
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#0a0f1d] text-slate-200">
      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-40 w-80 glass-panel border-r border-white/5 transition-transform duration-300 lg:relative lg:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0 pt-16' : '-translate-x-full lg:translate-x-0'}`}>
        <div className="h-full flex flex-col p-6 space-y-8 overflow-y-auto">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-500/20">
              <Sparkles className="text-white w-6 h-6" />
            </div>
            <span className="font-bold text-xl tracking-tight">DreamGen AI</span>
          </div>

          {/* Setup Guide / Key Status */}
          <section className={`p-4 rounded-2xl border transition-all ${!isKeySelected ? 'bg-red-500/10 border-red-500/50 animate-pulse' : 'bg-slate-900/50 border-white/5'}`}>
            <div className="flex items-center gap-3 mb-3">
              <Key className={`w-4 h-4 ${!isKeySelected ? 'text-red-400' : 'text-blue-400'}`} />
              <h3 className="text-[10px] font-black uppercase tracking-widest">API Configuration</h3>
            </div>
            {!isKeySelected ? (
              <div className="space-y-3">
                <p className="text-[10px] text-red-300 font-medium leading-tight">No key detected. You must select a project to use the AI.</p>
                <button onClick={handleSelectKey} className="w-full py-2 bg-red-500 text-white rounded-xl text-[10px] font-black uppercase tracking-tighter">Select API Key</button>
              </div>
            ) : (
              <div className="flex items-center justify-between">
                <span className="text-[10px] text-green-400 font-bold flex items-center gap-1"><ShieldCheck className="w-3 h-3" /> Ready to Create</span>
                <button onClick={handleSelectKey} className="text-[9px] text-slate-500 hover:text-white underline">Switch Key</button>
              </div>
            )}
          </section>

          {/* Mode Selector */}
          <section className="p-4 bg-gradient-to-br from-purple-900/20 to-blue-900/20 rounded-2xl border border-white/10">
            <div className="flex items-center justify-between">
              <div className="flex flex-col">
                <h3 className="text-[10px] font-black text-purple-300 uppercase tracking-widest">Masterpiece Mode</h3>
                <span className="text-[8px] text-purple-400/80 font-bold uppercase">Pro (Requires Billing)</span>
              </div>
              <div 
                className={`w-10 h-5 rounded-full p-1 cursor-pointer transition-colors ${settings.useProModel ? 'bg-purple-600' : 'bg-slate-700'}`}
                onClick={() => setSettings({ ...settings, useProModel: !settings.useProModel })}
              >
                <div className={`w-3 h-3 bg-white rounded-full transition-transform ${settings.useProModel ? 'translate-x-5' : 'translate-x-0'}`} />
              </div>
            </div>
          </section>

          {/* Styles */}
          <section>
            <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">Art Styles</h3>
            <div className="grid grid-cols-2 gap-2">
              {STYLE_PRESETS.map((s) => (
