import React, { useState, useEffect, useRef } from 'react';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Download, 
  RefreshCw, 
  Trash2, 
  Layers,
  Check,
  AlertCircle,
  Menu,
  X,
  Star,
  ExternalLink,
  Key,
  ShieldCheck,
  Info,
  Gift,
  Zap
} from 'lucide-react';
import { 
  GeneratedImage, 
  GenerationSettings, 
  AspectRatio, 
  Resolution, 
  GenerationMode,
  PromptHistoryItem,
  FeaturedPrompt
} from './types';
import { 
  STYLE_PRESETS, 
  MOODS, 
  LIGHTING, 
  ASPECT_RATIOS, 
  RESOLUTIONS,
  FEATURED_PROMPTS
} from './constants';
import { generateImage, enhancePrompt, translatePrompt } from './geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'generate' | 'gallery'>('generate');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isKeySelected, setIsKeySelected] = useState<boolean>(true);

  const [prompt, setPrompt] = useState('');
  const [mode, setMode] = useState<GenerationMode>('text-to-image');
  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: '1:1',
    resolution: '1K',
    style: 'none',
    mood: 'Default',
    lighting: 'Default',
    colorTone: 'Default',
    negativePrompt: '',
    seed: null,
    numImages: 1,
    useProModel: false,
    useSearch: false
  });

  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentResult, setCurrentResult] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    checkKey();
    const saved = localStorage.getItem('dreamgen_gallery');
    if (saved) setGeneratedImages(JSON.parse(saved));
  }, []);

  const checkKey = async () => {
    if (typeof (window as any).aistudio !== 'undefined') {
      const selected = await (window as any).aistudio.hasSelectedApiKey();
      setIsKeySelected(selected || !!process.env.API_KEY);
    }
  };

  const handleSelectKey = async () => {
    if (typeof (window as any).aistudio !== 'undefined') {
      await (window as any).aistudio.openSelectKey();
      setIsKeySelected(true);
      setError(null);
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim() && !uploadedImage) {
      setError("Please describe what you want to create.");
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const translated = await translatePrompt(prompt);
      const results = await generateImage(translated, settings, mode, uploadedImage || undefined);
      setCurrentResult(results);

      const newItems = results.map(url => ({
        id: Math.random().toString(36).substr(2, 9),
        url,
        prompt,
        timestamp: Date.now(),
        settings: { ...settings }
      }));
      setGeneratedImages(prev => [...newItems, ...prev]);
      localStorage.setItem('dreamgen_gallery', JSON.stringify([...newItems, ...generatedImages]));
      setIsKeySelected(true);
    } catch (err: any) {
      const msg = err.message || "";
      console.error("Gen Error:", err);
      if (msg === "API_KEY_MISSING" || msg.includes("API Key must be set")) {
        setIsKeySelected(false);
        setError("API Key Missing: You need a free key to use the AI. Click 'Get Free Key' below.");
      } else if (msg === "MODEL_NOT_FOUND") {
        setError("Model unavailable: Your API Key might not support this model. Try disabling 'Masterpiece Mode' to use the Free Tier.");
      } else {
        setError(msg || "Generation failed. Try a simpler prompt or check your connection.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setUploadedImage(ev.target?.result as string);
        setMode('image-to-image');
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#0a0f1d] text-slate-200">
      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-40 w-80 glass-panel border-r border-white/5 transition-transform duration-300 lg:relative lg:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0 pt-16' : '-translate-x-full lg:translate-x-0'}`}>
        <div className="h-full flex flex-col p-6 space-y-8 overflow-y-auto">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-500/20">
              <Sparkles className="text-white w-6 h-6" />
            </div>
            <span className="font-bold text-xl tracking-tight">DreamGen AI</span>
          </div>

          {/* Setup Section */}
          <section className={`p-5 rounded-3xl border transition-all ${!isKeySelected ? 'bg-red-500/10 border-red-500/50' : 'bg-slate-900/50 border-white/5'}`}>
            <div className="flex items-center justify-between mb-4">
               <h3 className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                 <Key className={`w-3 h-3 ${!isKeySelected ? 'text-red-400' : 'text-blue-400'}`} />
                 AI Key Setup
               </h3>
               {isKeySelected && <Check className="w-3 h-3 text-green-500" />}
            </div>

            <div className="space-y-3">
              {!isKeySelected && (
                <p className="text-[10px] text-red-300 font-medium leading-tight mb-2 italic">You must link an API Key to generate images.</p>
              )}
              <button onClick={handleSelectKey} className={`w-full py-2.5 rounded-xl text-[10px] font-black uppercase transition-all ${!isKeySelected ? 'bg-red-500 text-white shadow-lg shadow-red-500/20' : 'bg-white/5 border border-white/10 hover:bg-white/10'}`}>
                {isKeySelected ? 'Switch Key' : 'Select API Key'}
              </button>
              <a 
                href="https://aistudio.google.com/app/apikey" 
                target="_blank" 
                rel="noreferrer" 
                className="flex items-center justify-center gap-2 w-full py-2 text-[10px] font-bold text-blue-400 hover:text-blue-300 transition-colors"
              >
                <Gift className="w-3 h-3" /> Get Free Key Here
              </a>
            </div>
          </section>

          {/* Model Quality Selector */}
          <section className="space-y-3">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Generation Tier</h3>
            <div className="grid grid-cols-2 gap-2">
               <button 
                onClick={() => setSettings({...settings, useProModel: false})}
                className={`flex flex-col items-center gap-1 p-3 rounded-2xl border transition-all ${!settings.useProModel ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-500/20' : 'bg-slate-900 border-white/5 text-slate-500 hover:border-white/20'}`}
               >
                 <Zap className="w-4 h-4" />
                 <span className="text-[9px] font-black uppercase">Standard</span>
                 <span className="text-[7px] opacity-80 uppercase">Free Tier</span>
               </button>
               <button 
                onClick={() => setSettings({...settings, useProModel: true})}
                className={`flex flex-col items-center gap-1 p-3 rounded-2xl border transition-all ${settings.useProModel ? 'bg-purple-600 border-purple-500 text-white shadow-lg shadow-purple-500/20' : 'bg-slate-900 border-white/5 text-slate-500 hover:border-white/20'}`}
               >
                 <Star className="w-4 h-4" />
                 <span className="text-[9px] font-black uppercase">Masterpiece</span>
                 <span className="text-[7px] opacity-80 uppercase">Pro/Paid</span>
