                <button key={s.id} onClick={() => setSettings({ ...settings, style: s.id })} className={`group relative aspect-video rounded-xl overflow-hidden border-2 transition-all ${settings.style === s.id ? 'border-blue-500' : 'border-transparent opacity-60 hover:opacity-100'}`}>
                  <img src={s.previewUrl} className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-black/40 flex items-center justify-center p-1"><span className="text-[8px] font-black uppercase text-center">{s.name}</span></div>
                </button>
              ))}
            </div>
