            <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-4">Ratio</h3>
            <div className="grid grid-cols-3 gap-2">
              {ASPECT_RATIOS.map((r) => (
                <button key={r.value} onClick={() => setSettings({ ...settings, aspectRatio: r.value })} className={`py-2 rounded-lg text-[10px] font-black border transition-all ${settings.aspectRatio === r.value ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-900 border-white/5 text-slate-400'}`}>{r.label}</button>
              ))}
            </div>
          </section>
        </div>
      </aside>

      {/* Main Content */}
