import React, { useState, useEffect, useRef } from 'react';
import { 
  Sparkles, 
  Image as ImageIcon, 
  Download, 
  RefreshCw, 
  Trash2, 
  AlertCircle,
  Menu,
  X,
  Star,
  ExternalLink,
  Zap,
  Wand2
} from 'lucide-react';
import { 
  GeneratedImage, 
  GenerationSettings, 
  GenerationMode
} from './types';
import { 
  STYLE_PRESETS, 
  ASPECT_RATIOS, 
  FEATURED_PROMPTS
} from './constants';
import { generateImage, enhancePrompt, translatePrompt } from './geminiService';

// IndexedDB Helper for Large Image Storage
const DB_NAME = 'DreamGenDB';
const STORE_NAME = 'images';

const initDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, 1);
    request.onupgradeneeded = () => {
      const db = request.result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

const saveImagesToDB = async (images: GeneratedImage[]) => {
  try {
    const db = await initDB();
    const tx = db.transaction(STORE_NAME, 'readwrite');
    const store = tx.objectStore(STORE_NAME);
    images.forEach(img => store.put(img));
    return new Promise((resolve, reject) => {
      tx.oncomplete = () => resolve(true);
      tx.onerror = () => reject(tx.error);
    });
  } catch (err) {
    console.error("DB Save Error:", err);
  }
};

const getImagesFromDB = async (): Promise<GeneratedImage[]> => {
  try {
    const db = await initDB();
    const tx = db.transaction(STORE_NAME, 'readonly');
    const store = tx.objectStore(STORE_NAME);
    const request = store.getAll();
    return new Promise((resolve, reject) => {
      request.onsuccess = () => resolve(request.result.sort((a, b) => b.timestamp - a.timestamp));
      request.onerror = () => reject(request.error);
    });
  } catch (err) {
    console.error("DB Load Error:", err);
    return [];
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'generate' | 'gallery'>('generate');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMobileMenuOpen, setMobileMenuOpen] = useState(false);

  const [prompt, setPrompt] = useState('');
  const [settings, setSettings] = useState<GenerationSettings>({
    aspectRatio: '1:1',
    resolution: '1K',
    style: 'none',
    mood: 'Default',
    lighting: 'Default',
    colorTone: 'Default',
    negativePrompt: '',
    seed: null,
    numImages: 1,
    useProModel: false,
    useSearch: false
  });

  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [editingImage, setEditingImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [currentResult, setCurrentResult] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const promptRef = useRef<HTMLTextAreaElement>(null);

  // Load from IndexedDB on startup
  useEffect(() => {
    getImagesFromDB().then(setGeneratedImages);
  }, []);

  const handleGenerate = async () => {
    const baseSource = editingImage || uploadedImage;
    if (!prompt.trim() && !baseSource) {
      setError("Please describe what you want to create or change.");
      return;
    }

    const aistudio = (window as any).aistudio;
    if (settings.useProModel && aistudio) {
      try {
        const hasKey = await aistudio.hasSelectedApiKey();
        if (!hasKey) {
          await aistudio.openSelectKey();
        }
      } catch (e) {
        console.warn("Key selection dialog failed to open", e);
      }
    }

    setIsLoading(true);
    setError(null);

    try {
      const currentMode: GenerationMode = editingImage ? 'image-to-image' : (uploadedImage ? 'image-to-image' : 'text-to-image');
      const translated = await translatePrompt(prompt);
      const results = await generateImage(translated, settings, currentMode, baseSource || undefined);

      setCurrentResult(results);

      const newItems: GeneratedImage[] = results.map(url => ({
        id: Math.random().toString(36).substr(2, 9),
        url,
        prompt,
        timestamp: Date.now(),
        settings: { ...settings },
        originalImage: baseSource || undefined
      }));

      const updatedGallery = [...newItems, ...generatedImages];
      setGeneratedImages(updatedGallery);

      // Use IndexedDB instead of localStorage
      await saveImagesToDB(newItems);

      setEditingImage(null);
    } catch (err: any) {
      console.error("Gen Error:", err);
      const msg = err.message || "Generation failed.";
      if (msg.includes("API_KEY is not defined") || msg.includes("valid key")) {
        setError("API configuration error. Please ensure you have selected a valid paid API key for 'Masterpiece' mode.");
        if (msg.includes("valid key") && aistudio) {
          await aistudio.openSelectKey();
        }
      } else {
        setError(msg);
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleStartRefine = (imageUrl: string) => {
    setEditingImage(imageUrl);
    setUploadedImage(null);
    setPrompt('');
    setActiveTab('generate');
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setTimeout(() => promptRef.current?.focus(), 500);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setUploadedImage(ev.target?.result as string);
        setEditingImage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleEnhance = async () => {
    if (!prompt) return;
    setIsLoading(true);
    const enhanced = await enhancePrompt(prompt);
    setPrompt(enhanced);
    setIsLoading(false);
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#0a0f1d] text-slate-200">
      <aside className={`fixed inset-y-0 left-0 z-40 w-80 glass-panel border-r border-white/5 transition-transform duration-300 lg:relative lg:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0 pt-16' : '-translate-x-full lg:translate-x-0'}`}>
        <div className="h-full flex flex-col p-6 space-y-8 overflow-y-auto">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-500/20">
              <Sparkles className="text-white w-6 h-6" />
            </div>
            <span className="font-bold text-xl tracking-tight">DreamGen AI</span>
          </div>

          <section className="space-y-3">
